const App = () => {
  const [mode, setMode] = useState<Mode>('id');
  const [selectedImage, setSelectedImage] = useState<ImageFile | null>(null);
  const [generatedImage, setGeneratedImage] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [prompt, setPrompt] = useState('');
  const [idOptions, setIdOptions] = useState<{
        clothing?: ClothingOption;
        clothingCustomization?: string;
        hairStyle?: HairOption;
        background?: BackgroundOption;
  }>({ background: 'white' });

  const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      try {
        const base64 = await fileToBase64(file);
        setSelectedImage({ base64, mimeType: file.type, name: file.name });
      } catch (error) {
        console.error("Error uploading file:", error);
      }
    }
  };

  const handleGenerate = async () => {
    setIsLoading(true);
    try {
        let finalPrompt = prompt;
        if (mode === 'id') {
             const parts = getPromptPart(idOptions);
             finalPrompt = `Create a professional ID photo/Passport photo. Head and shoulders shot. Facing forward. Even studio lighting. ${parts} ${prompt}`;
        } else if (mode === 'restore') {
            finalPrompt = `Restore this old photo to high definition 4K quality. Fix scratches, tears, and blurriness. Colorize if black and white. Enhance facial details naturally. ${prompt}`;
        } else if (mode === 'create') {
            finalPrompt = prompt;
        }

        if (mode === 'create') {
             if (!finalPrompt.trim()) {
                 alert("Vui lòng nhập mô tả ảnh bạn muốn tạo.");
                 setIsLoading(false);
                 return;
             }
             const result = await generateImage(finalPrompt);
             setGeneratedImage(`data:image/png;base64,${result}`);
        } else if (selectedImage) {
             const result = await editImageWithPrompt(selectedImage, finalPrompt);
             setGeneratedImage(`data:image/png;base64,${result}`);
        } else {
            alert("Vui lòng tải ảnh lên hoặc chọn chế độ 'Tạo Ảnh'.");
        }

    } catch (error) {
        console.error(error);
        alert('Có lỗi xảy ra trong quá trình xử lý. Vui lòng thử lại.');
    } finally {
        setIsLoading(false);
    }
  };

  const themeClasses = {
        bgPrimary: "bg-slate-900",
        bgSecondary: "bg-slate-800",
        textPrimary: "text-white",
        textSecondary: "text-slate-400",
        accentText: "text-cyan-400",
        accentTextStrong: "text-cyan-500",
        accentTextHover: "hover:text-cyan-300",
        border: "border-slate-700",
        borderSecondary: "border-slate-600",
        button: {
            bg: "bg-cyan-600",
            hoverBg: "hover:bg-cyan-500",
            text: "text-white"
        }
  };

  return (
    <div className={`min-h-screen ${themeClasses.bgPrimary} ${themeClasses.textPrimary} p-4 md:p-8 font-sans`}>
        <div className="max-w-6xl mx-auto">
            <header className="text-center mb-10">
                <h1 className={`text-4xl font-extrabold ${themeClasses.accentText} mb-2`}>AI Studio</h1>
                <p className={`${themeClasses.textSecondary}`}>Ảnh Thẻ Chuyên Nghiệp & Phục Hồi Ảnh Cũ</p>
            </header>

            <div className="flex justify-center mb-8 gap-4 flex-wrap">
                {(['id', 'restore', 'create'] as Mode[]).map((m) => (
                    <button
                        key={m}
                        onClick={() => setMode(m)}
                        className={`px-6 py-2 rounded-full font-semibold transition-all ${
                            mode === m 
                            ? `${themeClasses.button.bg} ${themeClasses.button.text} shadow-lg shadow-cyan-500/30` 
                            : `${themeClasses.bgSecondary} ${themeClasses.textSecondary} hover:bg-slate-700`
                        }`}
                    >
                        {m === 'id' ? 'Ảnh Thẻ & Thay Đồ' : m === 'restore' ? 'Phục Hồi Ảnh' : 'Tạo Ảnh Mới'}
                    </button>
                ))}
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
                {/* Input Section */}
                <div className={`${themeClasses.bgSecondary} rounded-2xl p-6 shadow-xl border ${themeClasses.border}`}>
                    <h2 className={`text-xl font-bold mb-6 ${themeClasses.textPrimary}`}>Cấu Hình</h2>

                    {mode !== 'create' && (
                        <div className="mb-6">
                            <label className={`block mb-2 font-medium ${themeClasses.textSecondary}`}>Tải Ảnh Lên</label>
                            <div className={`border-2 border-dashed ${themeClasses.borderSecondary} rounded-xl p-6 text-center hover:border-cyan-500/50 transition-colors cursor-pointer relative`}>
                                <input 
                                    type="file" 
                                    accept="image/*" 
                                    onChange={handleImageUpload} 
                                    className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
                                />
                                {selectedImage ? (
                                    <div className="flex items-center justify-center">
                                         <img src={`data:${selectedImage.mimeType};base64,${selectedImage.base64}`} alt="Uploaded" className="max-h-48 rounded-md" />
                                    </div>
                                ) : (
                                    <div className="text-slate-500">
                                        <p>Nhấn hoặc kéo thả ảnh vào đây</p>
                                    </div>
                                )}
                            </div>
                        </div>
                    )}

                    {mode === 'id' && (
                        <div className="space-y-4 mb-6">
                             <div>
                                <label className={`block mb-2 font-medium ${themeClasses.textSecondary}`}>Chọn Phông Nền</label>
                                <select 
                                    value={idOptions.background || 'white'}
                                    onChange={(e) => setIdOptions({...idOptions, background: e.target.value as BackgroundOption})}
                                    className={`w-full p-3 rounded-lg ${themeClasses.bgPrimary} ${themeClasses.textPrimary} border ${themeClasses.border} focus:border-cyan-500 focus:outline-none`}
                                >
                                    {backgroundOptions.map(opt => <option key={opt.id} value={opt.id}>{opt.label}</option>)}
                                </select>
                            </div>
                            <div>
                                <label className={`block mb-2 font-medium ${themeClasses.textSecondary}`}>Chọn Trang Phục</label>
                                <select 
                                    value={idOptions.clothing || ''}
                                    onChange={(e) => setIdOptions({...idOptions, clothing: e.target.value as ClothingOption})}
                                    className={`w-full p-3 rounded-lg ${themeClasses.bgPrimary} ${themeClasses.textPrimary} border ${themeClasses.border} focus:border-cyan-500 focus:outline-none`}
                                >
                                    <option value="">Giữ nguyên trang phục gốc</option>
                                    <optgroup label="Nam">
                                        {maleClothingOptions.map(opt => <option key={opt.id} value={opt.id}>{opt.label}</option>)}
                                    </optgroup>
                                    <optgroup label="Nữ">
                                        {femaleClothingOptions.map(opt => <option key={opt.id} value={opt.id}>{opt.label}</option>)}
                                    </optgroup>
                                </select>
                            </div>
                             <div>
                                <label className={`block mb-2 font-medium ${themeClasses.textSecondary}`}>Mô Tả Trang Phục Khác (Tùy chọn)</label>
                                <input
                                    type="text"
                                    value={idOptions.clothingCustomization || ''}
                                    onChange={(e) => setIdOptions({...idOptions, clothingCustomization: e.target.value})}
                                    placeholder="Ví dụ: Áo sơ mi xanh dương, cà vạt đỏ..."
                                    className={`w-full p-3 rounded-lg ${themeClasses.bgPrimary} ${themeClasses.textPrimary} border ${themeClasses.border} focus:border-cyan-500 focus:outline-none`}
                                />
                            </div>
                        </div>
                    )}

                    <div className="mb-6">
                        <label className={`block mb-2 font-medium ${themeClasses.textSecondary}`}>
                            {mode === 'create' ? 'Mô Tả Ảnh Muốn Tạo' : 'Yêu Cầu Thêm'}
                        </label>
                        <textarea
                            value={prompt}
                            onChange={(e) => setPrompt(e.target.value)}
                            placeholder={mode === 'create' ? "Mô tả chi tiết ảnh bạn muốn tạo..." : "Nhập yêu cầu chỉnh sửa thêm (nếu có)..."}
                            className={`w-full p-3 rounded-lg ${themeClasses.bgPrimary} ${themeClasses.textPrimary} border ${themeClasses.border} focus:border-cyan-500 focus:outline-none min-h-[100px]`}
                        />
                    </div>

                    <button
                        onClick={handleGenerate}
                        disabled={isLoading || (mode !== 'create' && !selectedImage)}
                        className={`w-full py-4 rounded-xl font-bold text-lg shadow-lg transition-all transform active:scale-95 ${
                            isLoading || (mode !== 'create' && !selectedImage)
                            ? 'bg-slate-700 text-slate-500 cursor-not-allowed'
                            : `${themeClasses.button.bg} ${themeClasses.button.hoverBg} ${themeClasses.button.text} shadow-cyan-500/20`
                        }`}
                    >
                        {isLoading ? (
                            <div className="flex items-center justify-center gap-2">
                                <Spinner /> Đang Xử Lý...
                            </div>
                        ) : 'Tạo Ngay'}
                    </button>
                </div>

                {/* Output Section */}
                <div className="flex flex-col gap-6">
                    <ImageDisplay
                        title="Kết Quả"
                        imageSrc={generatedImage}
                        isLoading={isLoading}
                        placeholderText={mode === 'create' ? "Ảnh được tạo sẽ hiển thị ở đây" : "Ảnh đã chỉnh sửa sẽ hiển thị ở đây"}
                        themeClasses={themeClasses}
                        downloadable={true}
                    />
                </div>
            </div>
        </div>
    </div>
  );
};

export default App;

import { GoogleGenAI, Modality, GenerateContentResponse, HarmCategory, HarmBlockThreshold } from "@google/genai";
import { ImageFile, IdAnalysisResult } from '../types';

export const editImageWithPrompt = async (
  image: ImageFile,
  prompt: string,
  modelName: string = 'flash',
  backgroundImage?: ImageFile | null
): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  let effectiveModel = 'gemini-2.5-flash-image';
  if (modelName === 'pro') {
      effectiveModel = 'gemini-3-pro-image-preview';
  } else if (modelName !== 'flash' && modelName.includes('gemini')) {
      effectiveModel = modelName;
  }

  console.log(`Using model: ${effectiveModel} (Requested: ${modelName})`);

  let retries = 2;
  let currentPrompt = prompt;

  while (retries >= 0) {
      try {
        const parts: any[] = [
            {
                inlineData: {
                  data: image.base64,
                  mimeType: image.mimeType,
                },
            }
        ];

        // Add background image if provided
        if (backgroundImage) {
            parts.push({
                inlineData: {
                    data: backgroundImage.base64,
                    mimeType: backgroundImage.mimeType,
                }
            });
        }

        parts.push({ text: currentPrompt });

        const response = await ai.models.generateContent({
          model: effectiveModel,
          contents: { parts: parts },
          config: {
            responseModalities: [Modality.IMAGE],
            safetySettings: [
              { category: HarmCategory.HARM_CATEGORY_HATE_SPEECH, threshold: HarmBlockThreshold.BLOCK_NONE },
              { category: HarmCategory.HARM_CATEGORY_DANGEROUS_CONTENT, threshold: HarmBlockThreshold.BLOCK_NONE },
              { category: HarmCategory.HARM_CATEGORY_SEXUALLY_EXPLICIT, threshold: HarmBlockThreshold.BLOCK_NONE },
              { category: HarmCategory.HARM_CATEGORY_HARASSMENT, threshold: HarmBlockThreshold.BLOCK_NONE },
            ],
          },
        });

        if (response.promptFeedback?.blockReason) {
          throw new Error(`Yêu cầu đã bị chặn vì lý do an toàn (${response.promptFeedback.blockReason}). Vui lòng điều chỉnh yêu cầu hoặc hình ảnh của bạn.`);
        }

        const candidate = response.candidates?.[0];
        if (!candidate) throw new Error("API không trả về kết quả hợp lệ.");

        if (candidate.finishReason && candidate.finishReason !== 'STOP') {
            const reasonText = candidate.finishReason === 'SAFETY' ? `an toàn (${candidate.finishReason})` : candidate.finishReason;
            throw new Error(`Kết quả đã bị lọc hoặc dừng vì lý do: ${reasonText}.`);
        }

        if (!candidate.content?.parts || candidate.content.parts.length === 0) {
          throw new Error("Phản hồi từ API không chứa dữ liệu hình ảnh hợp lệ.");
        }

        for (const part of candidate.content.parts) {
          if (part.inlineData) {
            return part.inlineData.data;
          }
        }
        throw new Error("Không tìm thấy dữ liệu hình ảnh trong phản hồi của API.");

      } catch (error: any) {
        let errorString = "";
        try {
            errorString = JSON.stringify(error);
            if (error.message) errorString += " " + error.message;
        } catch {
            errorString = String(error);
        }

        const isPermissionError = errorString.includes('403') || errorString.includes('PERMISSION_DENIED');

        if (isPermissionError && effectiveModel.includes('pro')) {
             console.warn(`Permission denied for ${effectiveModel}. Automatically falling back to Flash model.`);
             effectiveModel = 'gemini-2.5-flash-image';
             if (retries === 0) retries = 1; 
             continue;
        }

        console.error(`Error calling Gemini API (Retries left: ${retries}):`, error);

        if (retries > 0) {
            // Retry logic...
             if (errorString.includes('500') || errorString.includes('Internal')) {
                await new Promise(resolve => setTimeout(resolve, 2000));
                retries--;
                continue;
            }
        }

        let userMsg = "Lỗi không xác định.";
        if (isPermissionError) {
             userMsg = `Lỗi quyền truy cập API (403).`;
        } else if (errorString.includes('500')) {
            userMsg = "Lỗi máy chủ Google (500).";
        } else if (error instanceof Error) {
            userMsg = error.message;
        }

        if (retries <= 0) throw new Error(userMsg);
        retries--;
      }
  }
  throw new Error("Hệ thống không phản hồi sau nhiều lần thử.");
};

export const refinePrompt = async (text: string, mode: 'id' | 'restore' | 'create'): Promise<string> => {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const model = 'gemini-2.5-flash'; 
    try {
        const response = await ai.models.generateContent({
            model: model,
