import { GoogleGenAI, Modality, HarmCategory, HarmBlockThreshold } from "@google/genai";
import { ImageFile, IdAnalysisResult } from '../types';

export const editImageWithPrompt = async (
  image: ImageFile,
  prompt: string,
  modelName: string = 'flash',
  backgroundImage?: ImageFile | null
): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  let effectiveModel = 'gemini-2.5-flash-image';
  if (modelName === 'pro') {
      effectiveModel = 'gemini-3-pro-image-preview';
  } else if (modelName !== 'flash' && modelName.includes('gemini')) {
      effectiveModel = modelName;
  }

  console.log(`Using model: ${effectiveModel} (Requested: ${modelName})`);

  let retries = 2;
  let currentPrompt = prompt;

  while (retries >= 0) {
      try {
        const parts: any[] = [
            {
                inlineData: {
                  data: image.base64,
                  mimeType: image.mimeType,
                },
            }
        ];

        // Add background image if provided
        if (backgroundImage) {
            parts.push({
                inlineData: {
                    data: backgroundImage.base64,
                    mimeType: backgroundImage.mimeType,
                }
            });
        }

        parts.push({ text: currentPrompt });

        const response = await ai.models.generateContent({
          model: effectiveModel,
          contents: { parts: parts },
          config: {
            responseModalities: [Modality.IMAGE],
            safetySettings: [
              { category: HarmCategory.HARM_CATEGORY_HATE_SPEECH, threshold: HarmBlockThreshold.BLOCK_NONE },
              { category: HarmCategory.HARM_CATEGORY_DANGEROUS_CONTENT, threshold: HarmBlockThreshold.BLOCK_NONE },
              { category: HarmCategory.HARM_CATEGORY_SEXUALLY_EXPLICIT, threshold: HarmBlockThreshold.BLOCK_NONE },
              { category: HarmCategory.HARM_CATEGORY_HARASSMENT, threshold: HarmBlockThreshold.BLOCK_NONE },
            ],
          },
        });

        if (response.promptFeedback?.blockReason) {
          throw new Error(`Yêu cầu đã bị chặn vì lý do an toàn (${response.promptFeedback.blockReason}). Vui lòng điều chỉnh yêu cầu hoặc hình ảnh của bạn.`);
        }

        const candidate = response.candidates?.[0];
        if (!candidate) throw new Error("API không trả về kết quả hợp lệ.");

        if (candidate.finishReason && candidate.finishReason !== 'STOP') {
            const reasonText = candidate.finishReason === 'SAFETY' ? `an toàn (${candidate.finishReason})` : candidate.finishReason;
            throw new Error(`Kết quả đã bị lọc hoặc dừng vì lý do: ${reasonText}.`);
        }

        if (!candidate.content?.parts || candidate.content.parts.length === 0) {
          throw new Error("Phản hồi từ API không chứa dữ liệu hình ảnh hợp lệ.");
        }

        for (const part of candidate.content.parts) {
          if (part.inlineData) {
            return part.inlineData.data;
          }
        }
        throw new Error("Không tìm thấy dữ liệu hình ảnh trong phản hồi của API.");

      } catch (error: any) {
        let errorString = "";
        try {
            errorString = JSON.stringify(error);
            if (error.message) errorString += " " + error.message;
        } catch {
            errorString = String(error);
        }

        const isPermissionError = errorString.includes('403') || errorString.includes('PERMISSION_DENIED');

        if (isPermissionError && effectiveModel.includes('pro')) {
             console.warn(`Permission denied for ${effectiveModel}. Automatically falling back to Flash model.`);
             effectiveModel = 'gemini-2.5-flash-image';
             if (retries === 0) retries = 1; 
             continue;
        }

        console.error(`Error calling Gemini API (Retries left: ${retries}):`, error);

        if (retries > 0) {
            // Retry logic...
             if (errorString.includes('500') || errorString.includes('Internal')) {
                await new Promise(resolve => setTimeout(resolve, 2000));
                retries--;
                continue;
            }
        }

        let userMsg = "Lỗi không xác định.";
        if (isPermissionError) {
             userMsg = `Lỗi quyền truy cập API (403).`;
        } else if (errorString.includes('500')) {
            userMsg = "Lỗi máy chủ Google (500).";
        } else if (error instanceof Error) {
            userMsg = error.message;
        }

        if (retries <= 0) throw new Error(userMsg);
        retries--;
      }
  }
  throw new Error("Hệ thống không phản hồi sau nhiều lần thử.");
};

