export const generateImage = async (
    prompt: string,
    aspectRatio: string = '1:1',
    size: string = '1K'
): Promise<string> => {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    const usePro = size === '2K' || size === '4K';
    let targetModel = usePro ? 'gemini-3-pro-image-preview' : 'gemini-2.5-flash-image';
    let finalAspectRatio = aspectRatio === '21:9' ? '16:9' : aspectRatio;

    const callApi = async (model: string) => {
        const imageConfig: any = { aspectRatio: finalAspectRatio };
        if (model === 'gemini-3-pro-image-preview') imageConfig.imageSize = size;

        const response = await ai.models.generateContent({
            model: model,
            contents: { parts: [{ text: prompt }] },
            config: {
                imageConfig: imageConfig,
                safetySettings: [
                  { category: HarmCategory.HARM_CATEGORY_HATE_SPEECH, threshold: HarmBlockThreshold.BLOCK_NONE },
                  { category: HarmCategory.HARM_CATEGORY_DANGEROUS_CONTENT, threshold: HarmBlockThreshold.BLOCK_NONE },
                  { category: HarmCategory.HARM_CATEGORY_SEXUALLY_EXPLICIT, threshold: HarmBlockThreshold.BLOCK_NONE },
                  { category: HarmCategory.HARM_CATEGORY_HARASSMENT, threshold: HarmBlockThreshold.BLOCK_NONE },
                ]
            }
        });
        const candidate = response.candidates?.[0];
        if (!candidate?.content?.parts) throw new Error("No image generated.");
        for (const part of candidate.content.parts) {
            if (part.inlineData) return part.inlineData.data;
        }
        throw new Error("No data found.");
    };

    try {
        return await callApi(targetModel);
    } catch (error: any) {
        let errorString = "";
        try { errorString = JSON.stringify(error); if (error.message) errorString += " " + error.message; } catch { errorString = String(error); }

        if (errorString.includes('403') || errorString.includes('PERMISSION_DENIED')) {
            if (targetModel.includes('pro')) {
                console.warn("Permission denied for Pro. Fallback to Flash.");
                return await callApi('gemini-2.5-flash-image');
            }
        }
        throw new Error("Lỗi tạo ảnh: " + (error.message || "Unknown error"));
    }
};

export const analyzeImageAttributes = async (image: ImageFile): Promise<IdAnalysisResult> => {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    // Use Flash-Lite for analysis to save quota and reduce latency
    const model = 'gemini-2.5-flash-lite';

    const prompt = `
      Phân tích ảnh thẻ JSON:
      - gender: "Nam"/"Nữ"
      - ageRange: string
      - background: { isClean: boolean, color: string, description: string }
      - lighting: { isEven: boolean, description: string }
      - face: { isStraight: boolean, isClear: boolean, description: string }
      - quality: { isSharp: boolean, hasNoise: boolean, description: string }
      - overallPass: boolean
    `;

    try {
        const response = await ai.models.generateContent({
            model: model,
            contents: {
                parts: [
                    { inlineData: { data: image.base64, mimeType: image.mimeType } },
                    { text: prompt }
                ]
            },
            config: { responseMimeType: "application/json" }
        });

        let text = response.text;
        if (!text) throw new Error("No response");

        // Sanitize JSON input
        text = text.replace(/```json/g, '').replace(/```/g, '').trim();
        const start = text.indexOf('{');
        const end = text.lastIndexOf('}');
        if (start !== -1 && end !== -1) {
            text = text.substring(start, end + 1);
        }

        const parsed = JSON.parse(text);

        // Validate and apply defaults to ensure IdAnalysisResult shape
        return {
            gender: parsed.gender || "Không xác định",
            ageRange: parsed.ageRange || "--",
            background: {
                isClean: !!parsed.background?.isClean,
                color: parsed.background?.color || "Unknown",
                description: parsed.background?.description || "Không thể phân tích"
            },
            lighting: {
                isEven: !!parsed.lighting?.isEven,
                description: parsed.lighting?.description || "---"
            },
            face: {
                isStraight: !!parsed.face?.isStraight,
                isClear: !!parsed.face?.isClear,
                description: parsed.face?.description || "---"
            },
            quality: {
                isSharp: !!parsed.quality?.isSharp,
                hasNoise: !!parsed.quality?.hasNoise,
                description: parsed.quality?.description || "---"
            },
            overallPass: !!parsed.overallPass
        };
    } catch (e) {
        console.error("Analysis failed", e);
        return {
            gender: "Không xác định", ageRange: "--",
            background: { isClean: true, color: "Unknown", description: "Không thể phân tích" },
            lighting: { isEven: true, description: "---" },
            face: { isStraight: true, isClear: true, description: "---" },
            quality: { isSharp: true, hasNoise: false, description: "---" },
            overallPass: true
        };
    }
};

