                    setRestoreHistory(prev => [{ original: originalImage, edited: newEditedImageSrc }, ...prev].slice(0, 12));
                }
                break;
        }
    } catch (e) {
      if (e instanceof Error) { setError(e.message); } 
      else { setError('Một lỗi không mong muốn đã xảy ra.'); }
    } finally {
      setIsLoading(false);
    }
  };

  const handleHistoryClick = (item: HistoryItem) => {
    if (mode === 'create') {
        // For create mode, we just show the result
        setEditedImage(item.edited);
        if (item.prompt) setCreatePrompt(item.prompt);
    } else {
        if (item.original) setOriginalImage(item.original);
        setEditedImage(item.edited);
    }
    // Reset undo/redo for new session from history
    setEditStack([item.edited]);
    setCurrentEditIndex(0);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleClearHistory = (e: React.MouseEvent) => {
      e.preventDefault();
      e.stopPropagation();

      const currentHistory = mode === 'id' ? idHistory : (mode === 'restore' ? restoreHistory : createHistory);
      if (currentHistory.length === 0) return;

      setShowClearHistoryConfirm(true);
  };

  const confirmClearHistory = () => {
        if (mode === 'id') {
            setIdHistory([]);
        } else if (mode === 'restore') {
            setRestoreHistory([]);
        } else {
            setCreateHistory([]);
        }
