const AnalysisResultCard: React.FC<{ result: IdAnalysisResult; themeClasses: ThemeType }> = ({ result, themeClasses }) => {
    // Safety check to prevent crash if result is malformed
    if (!result || !result.background || !result.lighting || !result.quality || !result.face) return null;

    return (
        <div className={`mt-2 p-3 rounded-lg border ${themeClasses.borderSecondary} ${themeClasses.bgSecondary} text-xs sm:text-sm shadow-md`}>
            <h4 className={`font-bold mb-2 ${themeClasses.accentText}`}>Kết quả phân tích nhanh:</h4>
            <div className="space-y-1.5">
                <div className="flex justify-between">
                    <span className={themeClasses.textSecondary}>Giới tính:</span>
                    <span className="font-semibold">{result.gender}</span>
                </div>
                 <div className="flex justify-between">
                    <span className={themeClasses.textSecondary}>Độ tuổi:</span>
                    <span className="font-semibold">{result.ageRange}</span>
                </div>
                <div className="flex justify-between items-center">
                    <span className={themeClasses.textSecondary}>Phông nền:</span>
                    <span className={result.background.isClean ? "text-green-500" : "text-yellow-500"}>
                        {result.background.isClean ? "✓ Sạch" : "⚠ Chưa chuẩn"}
                    </span>
                </div>
                <p className="text-[10px] opacity-70 italic">{result.background.description}</p>

                <div className="flex justify-between items-center">
                    <span className={themeClasses.textSecondary}>Ánh sáng:</span>
                    <span className={result.lighting.isEven ? "text-green-500" : "text-yellow-500"}>
                        {result.lighting.isEven ? "✓ Tốt" : "⚠ Không đều"}
                    </span>
                </div>
                 <p className="text-[10px] opacity-70 italic">{result.lighting.description}</p>

                 <div className="flex justify-between items-center">
                    <span className={themeClasses.textSecondary}>Chất lượng:</span>
                    <span className={result.quality.isSharp ? "text-green-500" : "text-yellow-500"}>
                        {result.quality.isSharp ? "✓ Rõ nét" : "⚠ Mờ/Nhiễu"}
                    </span>
                </div>
                 <p className="text-[10px] opacity-70 italic">{result.quality.description}</p>

                 <div className={`mt-2 pt-2 border-t ${themeClasses.borderSecondary} text-center font-bold`}>
                    {result.overallPass ? (
                        <span className="text-green-400">ĐỦ TIÊU CHUẨN XỬ LÝ</span>
                    ) : (
                        <span className="text-red-400">KHUYẾN NGHỊ ĐỔI ẢNH KHÁC</span>
                    )}
                 </div>
            </div>
        </div>
    );
};

