          mode: mode,
          data: newPresetData
      };

      let updatedPresets;
      if (existingIndex !== -1) {
          updatedPresets = [...presets];
          updatedPresets[existingIndex] = newPreset;
      } else {
          updatedPresets = [...presets, newPreset];
      }

