  const handleSubmit = async (event?: React.FormEvent | React.MouseEvent) => {
    if(event) event.preventDefault();
    setIsLoading(true);
    setError(null);
    setEditedImage(null);

    try {
        switch (mode) {
            case 'create':
                const promptToUseCreate = createPrompt.trim();
