                const isDefaultID = mode === 'id' && !idOptions.clothing && !idOptions.clothingCustomization?.trim() && !idOptions.background?.trim() && idOptions.smoothSkin === 'none' && !customPrompt?.trim() && !idOptions.hair?.trim() && !idOptions.hairStyle && !idOptions.accessories?.trim() && idOptions.adjustLighting === 'none' && idOptions.increaseContrast === 'none' && idOptions.increaseSharpness === 'none' && idOptions.colorTemperature === 'normal' && idOptions.whiteBalance === 'neutral' && !advancedTech.hdr && advancedTech.microDetails === 'off' && !advancedTech.smartLight && idOptions.faceEnhancement === 'default' && idOptions.resolutionBoost === 'none' && !idOptions.facialRetouching?.brightenEyes && !idOptions.facialRetouching?.evenEyeSkin && !idOptions.facialRetouching?.smoothFineLines && !idOptions.facialRetouching?.lightMakeup && !idOptions.facialRetouching?.acneRemoval && !idOptions.facialRetouching?.teethWhitening;

                if (isDefaultID) {
                     // Optionally warn user, but allowed to proceed with default prompt
                }

                const promptToUse = finalEditPrompt;

                // Call API
                const resultBase64 = await editImageWithPrompt(
                    originalImage, 
                    promptToUse, 
                    selectedModel,
                    customBackgroundImage
                );
                const newImage2 = `data:image/png;base64,${resultBase64}`; // Helper often returns raw base64 or prefixed? editImageWithPrompt returns raw.

                // Ensure prefix
                const finalSrc = newImage2.startsWith('data:') ? newImage2 : `data:image/png;base64,${resultBase64}`;
                setEditedImage(finalSrc);

                const historyItem: HistoryItem = {
                    original: originalImage,
                    edited: finalSrc,
                    prompt: promptToUse
                };

                if (mode === 'id') setIdHistory(prev => [historyItem, ...prev].slice(0, 12));
                else setRestoreHistory(prev => [historyItem, ...prev].slice(0, 12));

                const newStack = editStack.slice(0, currentEditIndex + 1);
                newStack.push(finalSrc);
                setEditStack(newStack);
                setCurrentEditIndex(newStack.length - 1);
                break;
        }
    } catch (e: any) {
        setError(e.message || "Đã xảy ra lỗi.");
    } finally {
        setIsLoading(false);
    }
  };

