                            <svg className="h-5 w-5 text-red-400 mr-2 mt-0.5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4m0 4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
                            <span>{error}</span>
                        </div>
                    )}

                    <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                        {/* Original */}
                        {mode !== 'create' && (
                            <ImageDisplay 
                                title="Ảnh Gốc" 
                                imageSrc={getOriginalImageSrc()} 
                                placeholderText="Chưa có ảnh nào được tải lên" 
                                themeClasses={themeClasses} 
                            />
                        )}

                        {/* Result */}
                        <div className={mode === 'create' ? 'md:col-span-2' : ''}>
                             <ImageDisplay 
                                title={mode === 'create' ? "Kết Quả AI" : "Ảnh Đã Xử Lý"} 
                                imageSrc={editedImage} 
                                isLoading={isLoading}
                                placeholderText="Kết quả sẽ hiển thị tại đây" 
                                themeClasses={themeClasses}
                                downloadable={!!editedImage}
                             />
                             {/* Undo/Redo Controls for Result */}
                             {editedImage && (
                                 <div className="flex justify-center space-x-4 mt-4">
                                     <button onClick={handleUndo} disabled={currentEditIndex <= 0} className={`p-2 rounded-full ${themeClasses.bgTertiary} hover:bg-opacity-80 disabled:opacity-30`} title="Hoàn tác"><UndoIcon/></button>
                                     <button onClick={handleRedo} disabled={currentEditIndex >= editStack.length - 1} className={`p-2 rounded-full ${themeClasses.bgTertiary} hover:bg-opacity-80 disabled:opacity-30`} title="Làm lại"><RedoIcon/></button>
                                 </div>
                             )}
                        </div>
                    </div>

                    {/* History Bar */}
                    {(idHistory.length > 0 || restoreHistory.length > 0 || createHistory.length > 0) && (
                        <div className={`mt-8 pt-6 border-t ${themeClasses.borderSecondary}`}>
                            <div className="flex justify-between items-center mb-4">
                                <h3 className={`text-lg font-bold ${themeClasses.accentText}`}>Lịch sử</h3>
                                <button onClick={() => setShowClearHistoryConfirm(true)} className="text-xs text-red-400 hover:text-red-300 flex items-center"><TrashIcon /> Xóa lịch sử</button>
                            </div>
                            <div className="flex space-x-4 overflow-x-auto pb-4 custom-scrollbar">
                                {(mode === 'id' ? idHistory : (mode === 'restore' ? restoreHistory : createHistory)).map((item, idx) => (
                                    <div key={idx} onClick={() => handleHistorySelect(item)} className="flex-shrink-0 cursor-pointer w-24 group relative">
                                        <div className="h-24 w-24 rounded-lg overflow-hidden border border-gray-600 hover:border-blue-400 transition-all">
                                            <img src={item.edited} alt="History" className="w-full h-full object-cover" />
                                        </div>
                                    </div>
                                ))}
                            </div>
                        </div>
                    )}
                </div>
            </div>
        </div>

        {/* Modal: Save Preset */}
        {showSavePresetModal && (
            <div className="fixed inset-0 bg-black/70 flex items-center justify-center z-[60] backdrop-blur-sm">
                <div className={`${themeClasses.bgSecondary} p-6 rounded-xl w-96 shadow-2xl border ${themeClasses.border}`}>
                    <h3 className={`text-lg font-bold mb-4 ${themeClasses.textPrimary}`}>Lưu cấu hình hiện tại</h3>
                    <input 
                        type="text" 
                        value={presetNameInput} 
                        onChange={(e) => setPresetNameInput(e.target.value)}
                        placeholder="Đặt tên cho cấu hình..." 
                        className={`w-full p-3 rounded-lg mb-4 ${themeClasses.bgInput} ${themeClasses.textPrimary} border ${themeClasses.borderSecondary}`}
                        autoFocus
                    />
                    <div className="flex justify-end space-x-3">
                        <button onClick={() => setShowSavePresetModal(false)} className={`px-4 py-2 rounded-lg ${themeClasses.textSecondary} hover:bg-gray-700`}>Hủy</button>
                        <button onClick={handleSavePresetConfirm} className={`px-4 py-2 rounded-lg bg-blue-600 text-white font-bold hover:bg-blue-500`}>Lưu</button>
                    </div>
                </div>
            </div>
        )}

        {/* Modal: Clear History Confirm */}
        {showClearHistoryConfirm && (
            <div className="fixed inset-0 bg-black/70 flex items-center justify-center z-[60] backdrop-blur-sm">
                 <div className={`${themeClasses.bgSecondary} p-6 rounded-xl w-80 shadow-2xl border ${themeClasses.border}`}>
                    <h3 className={`text-lg font-bold mb-2 text-red-400`}>Xác nhận xóa?</h3>
                    <p className={`text-sm ${themeClasses.textSecondary} mb-4`}>Toàn bộ lịch sử chỉnh sửa của chế độ này sẽ bị xóa vĩnh viễn.</p>
                    <div className="flex justify-end space-x-3">
                        <button onClick={() => setShowClearHistoryConfirm(false)} className={`px-4 py-2 rounded-lg ${themeClasses.textSecondary} hover:bg-gray-700`}>Hủy</button>
                        <button onClick={handleClearHistory} className={`px-4 py-2 rounded-lg bg-red-600 text-white font-bold hover:bg-red-500`}>Xóa Tất Cả</button>
                    </div>
                </div>
            </div>
        )}

    </div>
  );
};

export default App;

