        else if (restoreOptions.skinTexture === 'medium') detailPrompts.push("Skin Texture: Medium detail.");
        else detailPrompts.push("Skin Texture: Soft detail.");
    }

    // Denoise
    if (restoreOptions.denoiseLevel === 'low') detailPrompts.push("Denoising: Low. Preserve subtle film grain.");
    if (restoreOptions.denoiseLevel === 'medium') detailPrompts.push("Denoising: Medium. Balance noise removal and detail.");
    if (restoreOptions.denoiseLevel === 'high') detailPrompts.push("Denoising: High. Remove all digital noise and grain for a clean look.");

    // Sharpness
    if (restoreOptions.sharpnessStrength === 'low') detailPrompts.push("Sharpness: Gentle.");
    if (restoreOptions.sharpnessStrength === 'medium') detailPrompts.push("Sharpness: Standard edge enhancement.");
    if (restoreOptions.sharpnessStrength === 'high') detailPrompts.push("Sharpness: Strong detail extraction.");

    // Upscale
    if (restoreOptions.resolutionBoost !== 'none') {
        detailPrompts.push(`Super-Resolution: Upscale image by factor ${restoreOptions.resolutionBoost}. Synthesize missing high-frequency details during upscaling.`);
    }
    parts.push("\n## 4. ENHANCEMENT & UPSCALING\n" + detailPrompts.map(p => `- ${p}`).join("\n"));

    // Section 5: Artistic Style
    if (restoreEffect) {
        parts.push("\n## 5. FINAL AESTHETIC");
        if (restoreEffect === 'film') parts.push("- Style: Vintage Film (Add subtle grain, slight vignette, retro color grading).");
        if (restoreEffect === 'sepia') parts.push("- Style: Sepia (Warm monochromatic antique tone).");
        if (restoreEffect === 'bw') parts.push("- Style: Black & White (High contrast, dramatic monochrome).");
    }

    // Section 6: Advanced Tech 2025 (Shared)
    const techParts = [];
    if (advancedTech.hdr) {
        techParts.push("HDR Processing: Recover detail in deep shadows and crushed blacks.");
    }
    if (advancedTech.microDetails !== 'off') {
        const intensity = advancedTech.microDetails;
        techParts.push(`Texture Synthesis (${intensity}): Generate micro-details (fabric weave, paper texture) to prevent 'smooth' AI look.`);
    }
    if (advancedTech.smartLight) {
        techParts.push("Smart Lighting & Global Illumination: Correct uneven lighting caused by camera flash or fading. Rebalance exposure for a natural look.");
    }
    if (techParts.length > 0) {
        parts.push("\n## 6. ADVANCED PROCESSING\n" + techParts.map(p => `- ${p}`).join("\n"));
    }

    if (restoreCustomPrompt?.trim()) {
        parts.push(`\n## 7. USER NOTES\n- ${restoreCustomPrompt.trim()}`);
    }

    return parts.join("\n");
  }, [restoreOptions, restoreEffect, restoreCustomPrompt, selectedModel, advancedTech, restoreEngines]);

  const finalEditPrompt = useMemo(() => {
    if (mode === 'id') return generateIdPrompt();
    if (mode === 'restore') return generateRestorePrompt();
    return '';
  }, [mode, generateIdPrompt, generateRestorePrompt]);

  const getOriginalImageSrc = useCallback(() => {
    if (!originalImage) return null;
    return `data:${originalImage.mimeType};base64,${originalImage.base64}`;
  }, [originalImage]);

  const handleSubmit = async (event?: React.FormEvent | React.MouseEvent) => {
    if(event) event.preventDefault();
    setIsLoading(true);
    setError(null);
    setEditedImage(null);

    try {
        switch (mode) {
            case 'create':
                const promptToUse = createPrompt.trim();
                if (!promptToUse) throw new Error("Vui lòng nhập mô tả ảnh.");
                const base64 = await generateImage(promptToUse, createAspectRatio, createSize);
                const newImage = `data:image/png;base64,${base64}`;
                setEditedImage(newImage);
                // Create mode doesn't have an original image, just prompt
                setCreateHistory(prev => [{ original: null, edited: newImage, prompt: promptToUse }, ...prev].slice(0, 50));
                // Add to Undo/Redo stack (though simpler for create)
                const newStackCreate = editStack.slice(0, currentEditIndex + 1);
                newStackCreate.push(newImage);
                setEditStack(newStackCreate);
                setCurrentEditIndex(newStackCreate.length - 1);
                break;
            case 'id':
            case 'restore':
                if (!originalImage) {
                    throw new Error('Vui lòng tải ảnh lên trước.');
                }
                if (mode === 'id' && !idOptions.clothing && !idOptions.clothingCustomization?.trim() && !idOptions.background?.trim() && idOptions.smoothSkin === 'none' && !customPrompt?.trim() && !idOptions.hair?.trim() && !idOptions.hairStyle && !idOptions.accessories?.trim() && idOptions.adjustLighting === 'none' && idOptions.increaseContrast === 'none' && idOptions.increaseSharpness === 'none' && idOptions.colorTemperature === 'normal' && idOptions.whiteBalance === 'neutral' && !advancedTech.hdr && advancedTech.microDetails === 'off' && !advancedTech.smartLight && idOptions.faceEnhancement === 'default' && idOptions.resolutionBoost === 'none' && !idOptions.facialRetouching?.brightenEyes && !idOptions.facialRetouching?.evenEyeSkin && !idOptions.facialRetouching?.smoothFineLines && !idOptions.facialRetouching?.lightMakeup && !idOptions.facialRetouching?.acneRemoval && !idOptions.facialRetouching?.teethWhitening && idOptions.skinTone === 'default' && idOptions.poreVisibility === 'natural' && idOptions.skinTexture === 'medium') {
                    throw new Error('Vui lòng chọn ít nhất một tùy chọn chỉnh sửa hoặc nhập yêu cầu.');
                }

                // Pass the selected model state ('flash' or 'pro') to the service
                const editedBase64 = await editImageWithPrompt(
                    originalImage, 
                    finalEditPrompt, 
                    selectedModel, 
                    mode === 'id' && idOptions.backgroundType === 'custom' ? customBackgroundImage : null
                );
                const newEditedImageSrc = `data:${originalImage.mimeType};base64,${editedBase64}`;

                // --- UPDATE STATE WITH UNDO/REDO STACK ---
                const newStack = editStack.slice(0, currentEditIndex + 1);
                newStack.push(newEditedImageSrc);
                setEditStack(newStack);
                setCurrentEditIndex(newStack.length - 1);
                setEditedImage(newEditedImageSrc);

                // Update persistent history gallery
                if (mode === 'id') {
                    setIdHistory(prev => [{ original: originalImage, edited: newEditedImageSrc }, ...prev].slice(0, 50));
                } else if (mode === 'restore') {
                    setRestoreHistory(prev => [{ original: originalImage, edited: newEditedImageSrc }, ...prev].slice(0, 50));
                }
                break;
        }
    } catch (e) {
      if (e instanceof Error) { setError(e.message); } 
      else { setError('Một lỗi không mong muốn đã xảy ra.'); }
    } finally {
      setIsLoading(false);
    }
  };

  const handleHistoryClick = (item: HistoryItem) => {
    if (mode === 'create') {
        // For create mode, we just show the result
        setEditedImage(item.edited);
        if (item.prompt) setCreatePrompt(item.prompt);
    } else {
        if (item.original) setOriginalImage(item.original);
        setEditedImage(item.edited);
    }
    // Reset undo/redo for new session from history
    setEditStack([item.edited]);
    setCurrentEditIndex(0);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleClearHistory = () => {
      if (mode === 'id') setIdHistory([]);
      else if (mode === 'restore') setRestoreHistory([]);
      else setCreateHistory([]);
      setShowClearHistoryConfirm(false);
  };

  return (
    <div className={`min-h-screen ${themeClasses.bgPrimary} ${themeClasses.textPrimary} font-sans transition-colors duration-300`}>
      {/* Header */}
      <header className={`sticky top-0 z-40 ${themeClasses.bgSecondary} border-b ${themeClasses.border} backdrop-blur-md bg-opacity-90`}>
        <div className="container mx-auto px-4 py-3 flex justify-between items-center">
            <div className="flex items-center space-x-2">
                <div className={`p-2 rounded-lg bg-gradient-to-br ${themeClasses.gradientFrom} ${themeClasses.gradientTo}`}>
                    <SparklesIcon />
                </div>
                <h1 className="text-xl font-bold tracking-tight hidden sm:block">Gemini Photo Studio</h1>
            </div>

            <div className="relative">
                <button 
                    onClick={() => setIsThemeMenuOpen(!isThemeMenuOpen)}
                    className={`p-2 rounded-full ${themeClasses.navButton.hoverBg}`}
                >
                    <span className="sr-only">Theme</span>
                    <div className={`w-5 h-5 rounded-full bg-gradient-to-tr ${themeClasses.gradientFrom} ${themeClasses.gradientTo}`}></div>
                </button>

                {isThemeMenuOpen && (
                    <div className={`absolute right-0 mt-2 w-32 rounded-lg shadow-xl ${themeClasses.bgSecondary} border ${themeClasses.border} overflow-hidden`}>
                        {Object.keys(themes).map((t) => (
                            <button
                                key={t}
                                onClick={() => { setTheme(t as ThemeName); setIsThemeMenuOpen(false); }}
                                className={`w-full text-left px-4 py-2 text-sm ${theme === t ? themeClasses.accentText : themeClasses.textSecondary} hover:${themeClasses.bgTertiary}`}
                            >
                                {themes[t as ThemeName].name}
                            </button>
                        ))}
                    </div>
                )}
            </div>
        </div>
      </header>

      <main className="container mx-auto px-4 py-6 max-w-6xl">
        {/* Top Controls */}
        <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 mb-8">
             <div className="w-full md:w-auto flex bg-slate-800/10 rounded-lg p-1">
                <ModeNavButton targetMode="id" currentMode={mode} onClick={handleModeChange} themeClasses={themeClasses}>
                    Ảnh Thẻ
                </ModeNavButton>
                <ModeNavButton targetMode="restore" currentMode={mode} onClick={handleModeChange} themeClasses={themeClasses}>
                    Phục Hồi
                </ModeNavButton>
                <ModeNavButton targetMode="create" currentMode={mode} onClick={handleModeChange} themeClasses={themeClasses}>
                    Tạo Ảnh
                </ModeNavButton>
             </div>

             <div className="w-full md:w-64">
                <ModelSelector selectedModel={selectedModel} onSelect={setSelectedModel} themeClasses={themeClasses} />
             </div>
        </div>

        <div className="flex flex-col lg:flex-row gap-8 items-start">
            {/* Left Panel: Settings */}
            <div className="w-full lg:w-1/3 space-y-6">

                {/* Upload Section (ID/Restore) */}
                {mode !== 'create' && (
                    <div className={`${themeClasses.bgSecondary} p-4 rounded-xl shadow-sm border ${themeClasses.border}`}>
                        <h3 className={`font-semibold mb-4 ${themeClasses.accentText}`}>1. Tải ảnh lên</h3>
                        <div className="relative group">
                            <input 
                                type="file" 
                                onChange={handleImageUpload} 
                                accept="image/*"
                                className="absolute inset-0 w-full h-full opacity-0 cursor-pointer z-10"
                            />
                            <div className={`border-2 border-dashed ${themeClasses.borderSecondary} rounded-lg p-8 text-center transition-colors group-hover:${themeClasses.optionButton.activeBorder} ${themeClasses.bgInput}`}>
                                {originalImage ? (
                                    <div className="flex items-center justify-center space-x-2 text-green-500">
                                        <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M5 13l4 4L19 7"></path></svg>
                                        <span className="font-medium truncate max-w-[200px]">{originalImage.name}</span>
                                    </div>
                                ) : (
                                    <div className="flex flex-col items-center justify-center text-gray-500">
                                        <UploadIcon />
                                        <span className="mt-2 text-sm">Nhấn để tải ảnh</span>
                                    </div>
                                )}
                            </div>
                        </div>

                        {mode === 'id' && originalImage && (
                            <div className="mt-4">
                                <button 
                                    onClick={handleAnalyze} 
                                    disabled={isAnalyzing}
                                    className={`w-full py-2 rounded-lg text-sm font-medium border ${themeClasses.borderSecondary} hover:${themeClasses.bgTertiary} flex items-center justify-center`}
                                >
                                    {isAnalyzing ? <Spinner /> : <><AnalyzeIcon /> Phân tích ảnh</>}
                                </button>
                                {analysisResult && <AnalysisResultCard result={analysisResult} themeClasses={themeClasses} />}
                            </div>
                        )}
                    </div>
                )}

                {/* Settings Section */}
                <div className={`${themeClasses.bgSecondary} p-4 rounded-xl shadow-sm border ${themeClasses.border} max-h-[600px] overflow-y-auto custom-scrollbar`}>
                    <div className="flex justify-between items-center mb-4">
                        <h3 className={`font-semibold ${themeClasses.accentText}`}>2. Tùy chỉnh</h3>
                        <div className="flex space-x-2">
                             <button onClick={handleOpenSavePresetModal} className="text-xs hover:underline opacity-70">Lưu mẫu</button>
                             {presets.length > 0 && <span className="opacity-30">|</span>}
                             {presets.filter(p => p.mode === mode).length > 0 && (
                                 <select 
                                    className={`text-xs bg-transparent border-none focus:ring-0 cursor-pointer max-w-[100px]`}
                                    onChange={(e) => handleLoadPreset(e.target.value)}
                                    value=""
                                 >
                                     <option value="" disabled>Mẫu đã lưu...</option>
                                     {presets.filter(p => p.mode === mode).map(p => (
                                         <option key={p.id} value={p.id}>{p.name}</option>
                                     ))}
                                 </select>
                             )}
                        </div>
                    </div>

                    <div className="space-y-4">
                        {/* Render Options based on Mode */}
                        {mode === 'id' && (
                            <>
                                <div>
                                    <label className="text-xs font-semibold mb-2 block opacity-70">Giới tính</label>
                                    <div className="flex space-x-2">
                                        <OptionButton active={idOptions.gender === 'male'} onClick={() => handleGenderChange('male')} themeClasses={themeClasses}>Nam</OptionButton>
                                        <OptionButton active={idOptions.gender === 'female'} onClick={() => handleGenderChange('female')} themeClasses={themeClasses}>Nữ</OptionButton>
                                    </div>
                                </div>

                                <div>
                                    <label className="text-xs font-semibold mb-2 block opacity-70">Trang phục</label>
                                    <select 
                                        className={`w-full p-2 rounded-md text-sm ${themeClasses.bgInput} border ${themeClasses.borderSecondary}`}
                                        value={idOptions.clothing || ''}
                                        onChange={(e) => setIdOptions({...idOptions, clothing: e.target.value as ClothingOption || null})}
                                    >
                                        <option value="">-- Mặc định --</option>
                                        <optgroup label="Nam">
                                            {maleClothingOptions.map(o => <option key={o.id} value={o.id}>{o.label}</option>)}
                                        </optgroup>
                                        <optgroup label="Nữ">
                                            {femaleClothingOptions.map(o => <option key={o.id} value={o.id}>{o.label}</option>)}
                                        </optgroup>
                                        <optgroup label="Trẻ em (Nam)">
                                            {maleKidClothingOptions.map(o => <option key={o.id} value={o.id}>{o.label}</option>)}
                                        </optgroup>
                                        <optgroup label="Trẻ em (Nữ)">
                                            {femaleKidClothingOptions.map(o => <option key={o.id} value={o.id}>{o.label}</option>)}
                                        </optgroup>
                                    </select>
                                </div>

                                <div>
                                    <label className="text-xs font-semibold mb-2 block opacity-70">Kiểu tóc</label>
                                    <select 
                                        className={`w-full p-2 rounded-md text-sm ${themeClasses.bgInput} border ${themeClasses.borderSecondary}`}
                                        value={idOptions.hairStyle || ''}
                                        onChange={(e) => setIdOptions({...idOptions, hairStyle: e.target.value as HairOption || null})}
                                    >
                                        <option value="">-- Mặc định --</option>
                                        <option value="keep_original">Giữ nguyên tóc gốc</option>
                                        {idOptions.gender === 'male' ? (
                                             maleHairOptions.map(o => <option key={o.id} value={o.id}>{o.label}</option>)
                                        ) : (
                                             femaleHairOptions.map(o => <option key={o.id} value={o.id}>{o.label}</option>)
                                        )}
                                    </select>
                                </div>

                                <div>
                                    <label className="text-xs font-semibold mb-2 block opacity-70">Phông nền</label>
                                    <div className="grid grid-cols-2 gap-2 mb-2">
                                        <OptionButton active={idOptions.backgroundType === 'solid'} onClick={() => setIdOptions({...idOptions, backgroundType: 'solid'})} themeClasses={themeClasses}>Màu</OptionButton>
                                        <OptionButton active={idOptions.backgroundType === 'gradient'} onClick={() => setIdOptions({...idOptions, backgroundType: 'gradient'})} themeClasses={themeClasses}>Gradient</OptionButton>
                                        <OptionButton active={idOptions.backgroundType === 'pattern'} onClick={() => setIdOptions({...idOptions, backgroundType: 'pattern'})} themeClasses={themeClasses}>Họa tiết</OptionButton>
                                        <OptionButton active={idOptions.backgroundType === 'custom'} onClick={() => setIdOptions({...idOptions, backgroundType: 'custom'})} themeClasses={themeClasses}>Tùy chỉnh</OptionButton>
                                    </div>

                                    {idOptions.backgroundType === 'custom' ? (
                                        <div className="mt-2">
                                            <input type="file" onChange={handleBackgroundUpload} className="text-xs w-full" accept="image/*" />
                                            {customBackgroundImage && <p className="text-xs text-green-500 mt-1">Đã chọn: {customBackgroundImage.name}</p>}
                                        </div>
                                    ) : (
                                        <select 
                                            className={`w-full p-2 rounded-md text-sm ${themeClasses.bgInput} border ${themeClasses.borderSecondary}`}
                                            value={idOptions.background}
                                            onChange={(e) => setIdOptions({...idOptions, background: e.target.value})}
                                        >
                                            <option value="">-- Chọn --</option>
                                            {idOptions.backgroundType === 'solid' && backgroundPalette.map(c => <option key={c.name} value={c.name}>{c.name}</option>)}
                                            {idOptions.backgroundType === 'gradient' && gradientOptions.map(c => <option key={c.name} value={c.desc}>{c.name}</option>)}
                                            {idOptions.backgroundType === 'pattern' && patternOptions.map(c => <option key={c.name} value={c.desc}>{c.name}</option>)}
                                        </select>
                                    )}
                                </div>
                            </>
                        )}

                        {mode === 'restore' && (
                             <>
                                <div>
                                    <label className="text-xs font-semibold mb-2 block opacity-70">Chế độ xử lý</label>
                                    <div className="flex space-x-2">
                                        <OptionButton active={restoreOptions.workflow === 'standard'} onClick={() => setRestoreOptions({...restoreOptions, workflow: 'standard'})} themeClasses={themeClasses}>Tiêu chuẩn</OptionButton>
                                        <OptionButton active={restoreOptions.workflow === 'pro_studio'} onClick={() => setRestoreOptions({...restoreOptions, workflow: 'pro_studio'})} themeClasses={themeClasses}>Pro Studio</OptionButton>
                                    </div>
                                </div>
                                <div className="space-y-2">
                                    <ToggleSwitch label="Tô màu (Colorize)" checked={restoreOptions.colorize} onChange={(c) => setRestoreOptions({...restoreOptions, colorize: c})} themeClasses={themeClasses} />
                                    <ToggleSwitch label="Xóa vết xước" checked={restoreOptions.damageTypes.scratchesAndDust} onChange={(c) => setRestoreOptions({...restoreOptions, damageTypes: {...restoreOptions.damageTypes, scratchesAndDust: c}})} themeClasses={themeClasses} />
                                    <ToggleSwitch label="Phục hồi mặt (Face)" checked={restoreOptions.enhanceFaces} onChange={(c) => setRestoreOptions({...restoreOptions, enhanceFaces: c})} themeClasses={themeClasses} />
                                </div>
                                <div>
                                     <label className="text-xs font-semibold mb-2 block opacity-70">Upscale</label>
                                     <div className="grid grid-cols-4 gap-1">
                                         {['none', '2x', '4x', '8x'].map((opt) => (
                                             <OptionButton key={opt} active={restoreOptions.resolutionBoost === opt} onClick={() => setRestoreOptions({...restoreOptions, resolutionBoost: opt as UpscaleLevel})} themeClasses={themeClasses}>{opt === 'none' ? 'Off' : opt}</OptionButton>
                                         ))}
                                     </div>
                                </div>
                             </>
                        )}

                        {mode === 'create' && (
                            <>
                                <div>
                                    <label className="text-xs font-semibold mb-2 block opacity-70">Tỉ lệ khung hình</label>
                                    <div className="grid grid-cols-3 gap-2">
                                        {(['1:1', '16:9', '9:16', '4:3', '3:4'] as CreateAspectRatio[]).map((r) => (
                                            <OptionButton key={r} active={createAspectRatio === r} onClick={() => setCreateAspectRatio(r)} themeClasses={themeClasses}>{r}</OptionButton>
                                        ))}
                                    </div>
                                </div>
                                <div>
                                    <label className="text-xs font-semibold mb-2 block opacity-70">Kích thước</label>
                                    <div className="flex space-x-2">
                                        {(['1K', '2K', '4K'] as CreateSize[]).map((s) => (
                                            <OptionButton key={s} active={createSize === s} onClick={() => setCreateSize(s)} themeClasses={themeClasses}>{s}</OptionButton>
                                        ))}
                                    </div>
                                </div>
                                <ToggleSwitch label="Thinking Mode (2.5)" checked={createThinkingMode} onChange={setCreateThinkingMode} themeClasses={themeClasses} />
                            </>
                        )}

                        {/* Prompt Input Area */}
                         <div className="pt-4 border-t border-slate-700">
                            <div className="flex justify-between mb-2">
                                <label className="text-xs font-semibold opacity-70">Mô tả thêm (Prompt)</label>
                                <button 
                                    onClick={handleOptimizePrompt} 
                                    disabled={isOptimizingPrompt}
                                    className={`text-xs flex items-center ${themeClasses.accentText} hover:underline`}
                                >
                                    {isOptimizingPrompt ? <Spinner /> : <><BrainIcon /> Tối ưu bằng AI</>}
                                </button>
                            </div>
                            <textarea 
                                className={`w-full p-3 rounded-lg text-sm ${themeClasses.bgInput} border ${themeClasses.borderSecondary} focus:ring-2 focus:ring-opacity-50 min-h-[100px]`}
                                placeholder={mode === 'create' ? "Mô tả hình ảnh bạn muốn tạo..." : "Nhập yêu cầu chỉnh sửa cụ thể..."}
                                value={mode === 'id' ? customPrompt : (mode === 'restore' ? restoreCustomPrompt : createPrompt)}
                                onChange={(e) => {
                                    if (mode === 'id') setCustomPrompt(e.target.value);
                                    else if (mode === 'restore') setRestoreCustomPrompt(e.target.value);
                                    else setCreatePrompt(e.target.value);
                                }}
                            />
                        </div>

                        {/* Action Buttons */}
                        <div className="flex gap-2">
                            <button 
                                onClick={handleUndo} 
                                disabled={currentEditIndex <= 0}
                                className={`p-2 rounded-md ${themeClasses.bgTertiary} disabled:opacity-30`}
                            >
                                <UndoIcon />
                            </button>
                            <button 
                                onClick={handleRedo} 
                                disabled={currentEditIndex >= editStack.length - 1}
                                className={`p-2 rounded-md ${themeClasses.bgTertiary} disabled:opacity-30`}
                            >
                                <RedoIcon />
                            </button>
                            <button 
                                onClick={(e) => handleSubmit(e)}
                                disabled={isLoading}
                                className={`flex-grow py-3 rounded-lg font-bold shadow-lg flex items-center justify-center space-x-2 transition-transform hover:scale-[1.02] active:scale-[0.98] ${themeClasses.button.bg} ${themeClasses.button.text}`}
                            >
                                {isLoading ? <Spinner /> : <><MagicWandIcon /> <span>{mode === 'create' ? 'Tạo ảnh' : 'Xử lý ngay'}</span></>}
                            </button>
                        </div>

                        {error && (
                            <div className="p-3 bg-red-500/10 border border-red-500/50 rounded-lg text-red-400 text-xs">
                                {error}
                            </div>
                        )}
                    </div>
                </div>
            </div>

            {/* Right Panel: Display */}
            <div className="flex-grow w-full">
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4 h-full">
                    {/* Original Image Display */}
                    {mode !== 'create' && (
                        <ImageDisplay 
                            title="Ảnh gốc" 
                            imageSrc={getOriginalImageSrc()} 
                            placeholderText="Ảnh gốc sẽ hiện ở đây" 
                            themeClasses={themeClasses}
                        />
                    )}

                    {/* Result Image Display */}
                    <div className={mode === 'create' ? "md:col-span-2" : ""}>
                        <ImageDisplay 
                            title="Kết quả" 
                            imageSrc={editedImage} 
                            isLoading={isLoading}
                            placeholderText={mode === 'create' ? "Ảnh được tạo sẽ hiện ở đây" : "Kết quả xử lý sẽ hiện ở đây"} 
                            themeClasses={themeClasses}
                            downloadable={true}
                            downloadFilename={`gemini_studio_${Date.now()}.png`}
                        />
                    </div>
                </div>

                {/* History Strip */}
                <div className="mt-8">
                     <div className="flex justify-between items-center mb-4">
                        <h3 className={`font-semibold ${themeClasses.textSecondary}`}>Lịch sử</h3>
                        {((mode === 'id' && idHistory.length > 0) || (mode === 'restore' && restoreHistory.length > 0) || (mode === 'create' && createHistory.length > 0)) && (
                            <button 
                                onClick={() => setShowClearHistoryConfirm(true)}
                                className="text-xs text-red-400 hover:text-red-300 flex items-center"
                            >
                                <TrashIcon /> Xóa lịch sử
                            </button>
                        )}
                     </div>
                     <div className="flex space-x-4 overflow-x-auto pb-4 custom-scrollbar">
                        {(mode === 'id' ? idHistory : (mode === 'restore' ? restoreHistory : createHistory)).map((item, idx) => (
                            <div 
                                key={idx} 
                                onClick={() => handleHistoryClick(item)}
                                className="flex-shrink-0 w-24 h-24 rounded-lg overflow-hidden border border-transparent hover:border-blue-500 cursor-pointer relative group"
                            >
                                <img src={item.edited} className="w-full h-full object-cover" alt="History" />
                                <div className="absolute inset-0 bg-black/0 group-hover:bg-black/20 transition-all"></div>
                            </div>
                        ))}
                        {(mode === 'id' ? idHistory : (mode === 'restore' ? restoreHistory : createHistory)).length === 0 && (
                            <div className={`text-sm ${themeClasses.textSecondary} italic`}>Chưa có lịch sử.</div>
                        )}
                     </div>
                </div>
            </div>
        </div>
      </main>

      {/* Modals */}
      {showSavePresetModal && (
          <div className="fixed inset-0 bg-black/80 flex items-center justify-center z-50">
              <div className={`${themeClasses.bgSecondary} p-6 rounded-xl w-96 border ${themeClasses.border}`}>
                  <h3 className={`text-lg font-bold mb-4 ${themeClasses.textPrimary}`}>Lưu cấu hình hiện tại</h3>
                  <input 
                      type="text" 
                      value={presetNameInput}
                      onChange={(e) => setPresetNameInput(e.target.value)}
                      placeholder="Đặt tên cho mẫu..."
                      className={`w-full p-3 rounded-lg mb-4 ${themeClasses.bgInput} ${themeClasses.textPrimary}`}
                      autoFocus
                  />
                  <div className="flex justify-end space-x-3">
                      <button onClick={() => setShowSavePresetModal(false)} className={`px-4 py-2 rounded-lg ${themeClasses.bgTertiary}`}>Hủy</button>
                      <button onClick={handleSavePresetConfirm} className={`px-4 py-2 rounded-lg ${themeClasses.button.bg} text-white`}>Lưu</button>
                  </div>
              </div>
          </div>
      )}

      {showClearHistoryConfirm && (
          <div className="fixed inset-0 bg-black/80 flex items-center justify-center z-50">
              <div className={`${themeClasses.bgSecondary} p-6 rounded-xl w-96 border ${themeClasses.border}`}>
                  <h3 className={`text-lg font-bold mb-2 ${themeClasses.textPrimary}`}>Xác nhận xóa</h3>
                  <p className={`text-sm mb-6 ${themeClasses.textSecondary}`}>Bạn có chắc chắn muốn xóa toàn bộ lịch sử của chế độ này không?</p>
                  <div className="flex justify-end space-x-3">
                      <button onClick={() => setShowClearHistoryConfirm(false)} className={`px-4 py-2 rounded-lg ${themeClasses.bgTertiary}`}>Hủy</button>
                      <button onClick={handleClearHistory} className="px-4 py-2 rounded-lg bg-red-600 hover:bg-red-700 text-white">Xóa tất cả</button>
                  </div>
              </div>
          </div>
      )}

    </div>
  );
};

export default App;

