import React, { useState } from 'react';
import ImageDisplay from './components/ImageDisplay';
import { fileToBase64 } from './utils/fileUtils';
import { editImageWithPrompt, generateImage, analyzeImageAttributes } from './services/geminiService';
import { ImageFile, IdAnalysisResult } from './types';

// Theme configuration matching the application style
const themeClasses = {
  bgMain: 'bg-gray-900',
  bgSecondary: 'bg-gray-800',
  bgPrimary: 'bg-gray-700',
  textPrimary: 'text-gray-100',
  textSecondary: 'text-gray-400',
  accentText: 'text-blue-400',
  accentTextStrong: 'text-blue-500',
  accentTextHover: 'hover:text-blue-300',
  border: 'border-gray-700',
  borderSecondary: 'border-gray-600',
  bgInput: 'bg-gray-700 text-white',
  button: {
    bg: 'bg-blue-600',
    hoverBg: 'hover:bg-blue-700',
    text: 'text-white',
  }
};

type UpscaleLevel = 'none' | '2x' | '4x' | '8x';

interface OptionButtonProps {
    active: boolean;
    onClick: () => void;
    children: React.ReactNode;
    themeClasses: any;
}

const OptionButton: React.FC<OptionButtonProps> = ({ active, onClick, children, themeClasses }) => (
    <button
        onClick={onClick}
        className={`px-3 py-1 rounded text-xs font-medium transition-all border ${active 
            ? `${themeClasses.button.bg} border-transparent text-white` 
            : `border-gray-600 ${themeClasses.textSecondary} hover:bg-gray-700`}`}
    >
        {children}
    </button>
);

const backgroundPalette = [
    { name: 'White', value: '#FFFFFF' },
    { name: 'Blue', value: '#0000FF' },
    { name: 'Red', value: '#FF0000' },
    { name: 'Grey', value: '#808080' },
];

const gradientOptions = [
    { name: 'Blue Gradient', desc: 'blue gradient' },
    { name: 'Grey Gradient', desc: 'grey gradient' },
];

const patternOptions = [
    { name: 'Office', desc: 'office background' },
    { name: 'Nature', desc: 'nature background' },
];

function App() {
  const [selectedImage, setSelectedImage] = useState<ImageFile | null>(null);
  const [generatedImage, setGeneratedImage] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [prompt, setPrompt] = useState('');
  const [mode, setMode] = useState<'id' | 'create' | 'restore'>('id');

  const [idOptions, setIdOptions] = useState<any>({
      backgroundType: 'solid',
      background: 'White',
      resolutionBoost: 'none' as UpscaleLevel,
  });
  const [customBackgroundImage, setCustomBackgroundImage] = useState<ImageFile | null>(null);
  const [analysisResult, setAnalysisResult] = useState<IdAnalysisResult | null>(null);

  const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
      if (e.target.files && e.target.files[0]) {
          const file = e.target.files[0];
          try {
              const base64 = await fileToBase64(file);
              setSelectedImage({
                  base64,
                  mimeType: file.type,
                  name: file.name
              });
              setGeneratedImage(null);
              setAnalysisResult(null);
          } catch (err) {
              console.error(err);
              alert("Lỗi tải ảnh");
          }
      }
  };

  const handleBackgroundUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
      if (e.target.files && e.target.files[0]) {
          const file = e.target.files[0];
          try {
              const base64 = await fileToBase64(file);
              setCustomBackgroundImage({
                  base64,
                  mimeType: file.type,
                  name: file.name
              });
              setIdOptions({ ...idOptions, backgroundType: 'custom' });
          } catch (err) {
              console.error(err);
          }
      }
  };

  const handleGenerate = async () => {
      setIsLoading(true);
      setGeneratedImage(null);
      try {
          if (mode === 'create') {
              const result = await generateImage(prompt || 'A creative image');
              setGeneratedImage(result);
          } else if (mode === 'id' && selectedImage) {
              let bgDesc = idOptions.background;
              if (idOptions.backgroundType === 'custom' && !customBackgroundImage) {
                  alert("Vui lòng chọn ảnh nền tùy chỉnh");
                  setIsLoading(false);
                  return;
              }

              const finalPrompt = `Create a professional ID photo. 
              Background: ${idOptions.backgroundType === 'custom' ? 'use provided background image' : bgDesc}.
              Upscale: ${idOptions.resolutionBoost}.
              Ensure even lighting, clear face, compliant with ID standards.`;

              const result = await editImageWithPrompt(
                  selectedImage, 
                  finalPrompt, 
                  'gemini-2.5-flash-image',
                  idOptions.backgroundType === 'custom' ? customBackgroundImage : null
              );
              setGeneratedImage(result);

          } else if (mode === 'restore' && selectedImage) {
               const result = await editImageWithPrompt(
                  selectedImage, 
                  "Restore this old photo, remove scratches, improve quality, fix colors.", 
                  'gemini-2.5-flash-image'
              );
              setGeneratedImage(result);
          }
      } catch (e: any) {
          alert(e.message);
      } finally {
          setIsLoading(false);
      }
  };

  const handleAnalyze = async () => {
      if (!selectedImage) return;
      setIsLoading(true);
      try {
          const result = await analyzeImageAttributes(selectedImage);
          setAnalysisResult(result);
      } catch (e) {
          console.error(e);
      } finally {
          setIsLoading(false);
      }
  };

  return (
    <div className={`min-h-screen ${themeClasses.bgMain} ${themeClasses.textPrimary} p-4 md:p-8 font-sans`}>
        <div className="max-w-6xl mx-auto grid grid-cols-1 lg:grid-cols-2 gap-8">
            <div className="space-y-6">
                <h1 className="text-3xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-blue-400 to-purple-500 mb-6">
                    Gemini Photo Studio
                </h1>

                <div className={`flex p-1 rounded-lg ${themeClasses.bgSecondary}`}>
                    {(['id', 'create', 'restore'] as const).map((m) => (
                        <button
                            key={m}
                            onClick={() => setMode(m)}
                            className={`flex-1 py-2 rounded-md font-medium transition-all text-sm ${
                                mode === m 
                                ? `${themeClasses.button.bg} text-white shadow` 
                                : 'text-gray-400 hover:text-white'
                            }`}
                        >
                            {m === 'id' ? 'Ảnh thẻ' : m === 'create' ? 'Tạo ảnh' : 'Phục chế'}
                        </button>
                    ))}
                </div>

                <div className={`${themeClasses.bgSecondary} p-6 rounded-xl border ${themeClasses.border}`}>
                    {mode === 'create' ? (
                        <div>
                            <label className="block text-sm font-semibold mb-2">Mô tả ảnh</label>
                            <textarea
                                className={`w-full p-3 rounded-lg ${themeClasses.bgInput} border ${themeClasses.borderSecondary} focus:ring-2 focus:ring-blue-500 outline-none`}
                                rows={4}
                                placeholder="Mô tả chi tiết ảnh bạn muốn tạo..."
                                value={prompt}
                                onChange={(e) => setPrompt(e.target.value)}
                            />
                        </div>
                    ) : (
                        <div>
                             <label className="block text-sm font-semibold mb-2">Chọn ảnh gốc</label>
                             <input 
                                type="file" 
                                accept="image/*"
                                onChange={handleImageUpload}
                                className="block w-full text-sm text-gray-400 file:mr-4 file:py-2 file:px-4 file:rounded-full file:border-0 file:text-sm file:font-semibold file:bg-blue-600 file:text-white hover:file:bg-blue-700"
                             />
                             {selectedImage && (
                                 <div className="mt-4 border border-gray-600 rounded-lg p-2 bg-gray-900/50">
                                     <img src={`data:${selectedImage.mimeType};base64,${selectedImage.base64}`} alt="Source" className="max-h-48 mx-auto rounded" />
                                     {mode === 'id' && (
                                         <div className="text-center mt-2">
                                             <button 
                                                onClick={handleAnalyze}
                                                className="text-xs text-blue-400 hover:text-blue-300 underline"
                                             >
                                                 Phân tích ảnh
                                             </button>
                                         </div>
                                     )}
                                 </div>
                             )}
                        </div>
                    )}
                </div>

                {mode === 'id' && (
                    <div className={`${themeClasses.bgSecondary} p-6 rounded-xl border ${themeClasses.border}`}>
                        <h3 className="text-lg font-semibold mb-4 text-white">Tùy chỉnh Ảnh thẻ</h3>
                        <div className="grid grid-cols-1 gap-4">
                            <div>
                                <label className="text-xs font-semibold mb-2 block opacity-70">Loại nền</label>
                                <div className="flex space-x-2 mb-2">
                                    {['solid', 'gradient', 'pattern', 'custom'].map(t => (
                                        <OptionButton 
                                            key={t}
                                            active={idOptions.backgroundType === t}
                                            onClick={() => setIdOptions({...idOptions, backgroundType: t})}
                                            themeClasses={themeClasses}
                                        >
                                            {t === 'solid' ? 'Màu đơn' : t === 'gradient' ? 'Gradient' : t === 'pattern' ? 'Họa tiết' : 'Tùy chỉnh'}
                                        </OptionButton>
                                    ))}
                                </div>

                                {idOptions.backgroundType === 'custom' ? (
                                    <div className="mt-2">
                                        <input type="file" onChange={handleBackgroundUpload} className="text-xs w-full text-gray-400" accept="image/*" />
                                        {customBackgroundImage && <p className="text-xs text-green-500 mt-1">Đã chọn: {customBackgroundImage.name}</p>}
                                    </div>
                                ) : (
                                    <select 
                                        className={`w-full p-2 rounded-md text-sm ${themeClasses.bgInput} border ${themeClasses.borderSecondary}`}
                                        value={idOptions.background}
                                        onChange={(e) => setIdOptions({...idOptions, background: e.target.value})}
                                    >
                                        <option value="">-- Chọn --</option>
                                        {idOptions.backgroundType === 'solid' && backgroundPalette.map(c => <option key={c.name} value={c.name}>{c.name}</option>)}
                                        {idOptions.backgroundType === 'gradient' && gradientOptions.map(c => <option key={c.name} value={c.desc}>{c.name}</option>)}
                                        {idOptions.backgroundType === 'pattern' && patternOptions.map(c => <option key={c.name} value={c.desc}>{c.name}</option>)}
                                    </select>
                                )}
                            </div>

                            <div>
                                <label className="text-xs font-semibold mb-2 block opacity-70">Upscale (Siêu phân giải)</label>
                                <div className="flex space-x-2">
                                    {['none', '2x', '4x', '8x'].map((opt) => (
                                        <OptionButton 
                                            key={opt} 
                                            active={idOptions.resolutionBoost === opt} 
                                            onClick={() => setIdOptions({...idOptions, resolutionBoost: opt as UpscaleLevel})} 
                                            themeClasses={themeClasses}
                                        >
                                            {opt === 'none' ? 'Tắt' : opt}
                                        </OptionButton>
                                    ))}
                                </div>
                                {idOptions.resolutionBoost !== 'none' && (
                                    <p className="text-[10px] text-blue-400 mt-1 italic">
                                        * Tự động tái tạo chi tiết bị thiếu.
                                    </p>
                                )}
                            </div>
                        </div>
                    </div>
                )}

                <button
                    onClick={handleGenerate}
                    disabled={isLoading || (!selectedImage && mode !== 'create') || (mode === 'create' && !prompt)}
                    className={`w-full py-3 rounded-xl font-bold text-lg shadow-lg transition-all ${
                        isLoading || (!selectedImage && mode !== 'create')
                        ? 'bg-gray-600 cursor-not-allowed opacity-50' 
                        : `${themeClasses.button.bg} ${themeClasses.button.hoverBg} text-white`
                    }`}
                >
                    {isLoading ? 'Đang xử lý...' : 'Tạo / Xử lý'}
                </button>

                 {analysisResult && (
                    <div className={`${themeClasses.bgSecondary} p-4 rounded-lg border ${themeClasses.border} text-sm`}>
                        <h4 className="font-bold mb-2 text-white">Kết quả phân tích</h4>
                        <div className="grid grid-cols-2 gap-2 text-gray-300">
                            <p>Giới tính: <span className="text-white">{analysisResult.gender}</span></p>
                            <p>Tuổi: <span className="text-white">{analysisResult.ageRange}</span></p>
                            <p>Chất lượng: <span className={analysisResult.quality.isSharp ? 'text-green-400' : 'text-red-400'}>{analysisResult.quality.isSharp ? 'Rõ nét' : 'Mờ'}</span></p>
                            <p>Ánh sáng: <span className={analysisResult.lighting.isEven ? 'text-green-400' : 'text-yellow-400'}>{analysisResult.lighting.isEven ? 'Đều' : 'Không đều'}</span></p>
                        </div>
                        <p className="mt-2 text-xs opacity-70 italic">{analysisResult.face.description}</p>
                    </div>
                 )}
            </div>

            <div className="space-y-6">
                <ImageDisplay 
                    title="Kết quả"
                    imageSrc={generatedImage ? `data:image/png;base64,${generatedImage}` : null}
                    isLoading={isLoading}
                    placeholderText="Ảnh kết quả sẽ hiện ở đây"
                    themeClasses={themeClasses}
                    downloadable={true}
                />
            </div>
        </div>
    </div>
  );
}

export default App;

