        if (advancedTech.smartLight) parts.push("- 3D RELIGHTING: Re-light subject based on facial geometry.");
    }

    // 8. CUSTOM & NEGATIVE
    if (customPrompt?.trim()) {
        parts.push(`\n**7. SPECIFIC USER INSTRUCTIONS**\n- ${customPrompt.trim()}`);
    }

    parts.push(`\n**8. NEGATIVE PROMPT (AVOID)**
- Avoid: Distorted eyes, asymmetrical face, extra fingers, plastic skin, blurry details, bad anatomy.
- Avoid: Harsh shadows, over-exposure, artifacts, painting style, cartoon style (unless specified).
    `);

    return parts.join("\n");
  }, [idOptions, customPrompt, selectedModel, advancedTech, customBackgroundImage]);

