    if (colorParts.length > 0) parts.push("\n**5. COLOR GRADING**\n" + colorParts.join("\n"));

    // 7. TECH 2025
    if (advancedTech.hdr || advancedTech.microDetails !== 'off' || advancedTech.smartLight) {
        parts.push("\n**6. ADVANCED PROCESSING**");
        if (advancedTech.hdr) parts.push("- HDR: Maximize dynamic range. Recover highlights.");
        if (advancedTech.microDetails !== 'off') parts.push(`- MICRO-DETAILS (${advancedTech.microDetails}): Synthesize fabric weave, individual hair strands, skin imperfections for realism.`);
        if (advancedTech.smartLight) parts.push("- 3D RELIGHTING: Re-light subject based on facial geometry.");
    }

    // 8. CUSTOM & NEGATIVE
    if (customPrompt?.trim()) {
        parts.push(`\n**7. SPECIFIC USER INSTRUCTIONS**\n- ${customPrompt.trim()}`);
    }

    parts.push(`\n**8. NEGATIVE PROMPT (AVOID)**
- Avoid: Distorted eyes, asymmetrical face, extra fingers, plastic skin, blurry details, bad anatomy.
- Avoid: Harsh shadows, over-exposure, artifacts, painting style, cartoon style (unless specified).
    `);

    return parts.join("\n");
  }, [idOptions, customPrompt, selectedModel, advancedTech, customBackgroundImage]);

  const handleGenerate = async () => {
    if (!uploadedImage) {
      alert("Vui lòng tải lên một ảnh chân dung.");
      return;
    }
    setIsGenerating(true);
    try {
      const prompt = generateIdPrompt();
      const resultBase64 = await editImageWithPrompt(uploadedImage, prompt, selectedModel, customBackgroundImage);
      setGeneratedImage(`data:image/png;base64,${resultBase64}`);
    } catch (err: any) {
      console.error(err);
      alert(err.message || "Đã xảy ra lỗi khi tạo ảnh.");
    } finally {
      setIsGenerating(false);
    }
  };

  const handleOptionChange = (key: keyof IdOptions, value: any) => {
    setIdOptions(prev => ({ ...prev, [key]: value }));
  };

  return (
    <div className={`min-h-screen ${themeClasses.bgPrimary} flex flex-col items-center p-4`}>
      <header className="w-full max-w-6xl mb-6">
        <h1 className="text-3xl font-bold text-gray-800">AI ID Photo Generator</h1>
      </header>

      <div className="w-full max-w-6xl flex flex-col md:flex-row gap-6">

        {/* CONTROLS */}
        <div className={`w-full md:w-1/3 p-4 ${themeClasses.bgSecondary} rounded-xl shadow-lg flex flex-col gap-4 overflow-y-auto max-h-[90vh]`}>
          <h2 className="text-xl font-semibold mb-2">Cấu hình</h2>

          {/* Model Selection */}
          <div className="flex flex-col gap-2">
            <label className="font-medium text-sm">Model</label>
            <select 
              value={selectedModel} 
              onChange={(e) => setSelectedModel(e.target.value as 'flash' | 'pro')}
              className={`p-2 border ${themeClasses.border} rounded-md`}
            >
              <option value="flash">Flash (Nhanh)</option>
              <option value="pro">Pro (Chất lượng cao)</option>
            </select>
          </div>

          {/* Upload */}
          <div className="flex flex-col gap-2">
            <label className="font-medium text-sm">Ảnh gốc</label>
            <input type="file" onChange={(e) => handleImageUpload(e)} accept="image/*" className="text-sm" />
          </div>

          <hr className={themeClasses.border} />

          {/* Basic Options */}
          <div className="flex flex-col gap-2">
            <label className="font-medium text-sm">Tỷ lệ</label>
            <select 
              value={idOptions.aspectRatio} 
              onChange={(e) => handleOptionChange('aspectRatio', e.target.value)}
              className={`p-2 border ${themeClasses.border} rounded-md`}
            >
              <option value="3x4">3x4</option>
              <option value="4x6">4x6</option>
              <option value="1:1">1:1</option>
              <option value="original">Gốc</option>
            </select>
          </div>

           <div className="flex flex-col gap-2">
            <label className="font-medium text-sm">Trang phục</label>
            <select 
              value={idOptions.clothing} 
              onChange={(e) => handleOptionChange('clothing', e.target.value)}
              className={`p-2 border ${themeClasses.border} rounded-md`}
            >
              <option value="vest_nam">Vest Nam Xanh</option>
              <option value="vest_nam_den_no">Vest Nam Tuxedo</option>
              <option value="somi_nam_trang">Sơ mi Nam Trắng</option>
              <option value="vest_nu">Vest Nữ Đen</option>
              <option value="somi_nu_trang">Sơ mi Nữ Trắng</option>
              <option value="ao_dai_trang">Áo Dài Trắng</option>
              <option value="kid_boy_student">Học sinh Nam</option>
              <option value="kid_girl_student">Học sinh Nữ</option>
              {/* Add more options as needed */}
            </select>
          </div>

          <div className="flex flex-col gap-2">
             <label className="font-medium text-sm">Nền</label>
             <select
               value={idOptions.backgroundType}
               onChange={(e) => handleOptionChange('backgroundType', e.target.value)}
               className={`p-2 border ${themeClasses.border} rounded-md`}
             >
               <option value="solid">Màu đơn</option>
               <option value="gradient">Gradient</option>
               <option value="custom">Ảnh tùy chỉnh</option>
             </select>
             {idOptions.backgroundType === 'custom' ? (
                <input type="file" onChange={(e) => handleImageUpload(e, true)} accept="image/*" className="text-sm mt-1" />
             ) : (
                <input 
                  type="text" 
                  value={idOptions.background} 
                  onChange={(e) => handleOptionChange('background', e.target.value)}
                  placeholder="Màu sắc (vd: blue, white)"
                  className={`p-2 border ${themeClasses.border} rounded-md`}
                />
             )}
          </div>

          <div className="flex flex-col gap-2">
            <label className="font-medium text-sm">Yêu cầu thêm</label>
            <textarea 
              value={customPrompt}
              onChange={(e) => setCustomPrompt(e.target.value)}
              className={`p-2 border ${themeClasses.border} rounded-md h-20 text-sm`}
              placeholder="VD: Mắt nhìn thẳng, cười nhẹ..."
            />
          </div>

           <button 
            onClick={handleGenerate} 
            disabled={isGenerating || !uploadedImage}
            className={`mt-4 py-3 rounded-lg font-semibold ${themeClasses.button.bg} ${themeClasses.button.hoverBg} ${themeClasses.button.text} disabled:opacity-50 transition-colors shadow-md`}
           >
             {isGenerating ? "Đang xử lý..." : "Tạo ảnh ID"}
           </button>
        </div>

        {/* PREVIEW */}
        <div className="w-full md:w-2/3 flex flex-col gap-6">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
             <ImageDisplay 
                title="Ảnh gốc" 
                imageSrc={uploadedImage ? `data:${uploadedImage.mimeType};base64,${uploadedImage.base64}` : null} 
                placeholderText="Tải ảnh lên để bắt đầu"
                themeClasses={themeClasses}
             />
             <ImageDisplay 
                title="Kết quả AI" 
                imageSrc={generatedImage} 
                placeholderText="Kết quả sẽ hiển thị tại đây"
                isLoading={isGenerating}
                themeClasses={themeClasses}
                downloadable={true}
             />
          </div>
        </div>
      </div>
    </div>
  );
}

