                                            <OptionButton active={advancedTech.microDetails === 'low'} onClick={() => setAdvancedTech({...advancedTech, microDetails: 'low'})} themeClasses={themeClasses}>Nhẹ</OptionButton>
                                            <OptionButton active={advancedTech.microDetails === 'medium'} onClick={() => setAdvancedTech({...advancedTech, microDetails: 'medium'})} themeClasses={themeClasses}>Vừa</OptionButton>
                                            <OptionButton active={advancedTech.microDetails === 'high'} onClick={() => setAdvancedTech({...advancedTech, microDetails: 'high'})} themeClasses={themeClasses}>Cao</OptionButton>
                                        </div>
                                    </div>

                                    <ToggleSwitch checked={advancedTech.smartLight} onChange={(c) => setAdvancedTech({...advancedTech, smartLight: c})} label="Smart Relighting 3D" themeClasses={themeClasses} />
                                </div>
                            )}
                        </div>
                    )}

                    {/* CREATE MODE OPTIONS */}
                    {mode === 'create' && (
                        <div className="space-y-4">
                            <div className="space-y-2">
                                <label className={`text-sm font-bold ${themeClasses.textSecondary}`}>Mô tả hình ảnh muốn tạo:</label>
                                <div className="relative">
                                    <textarea 
                                        className={`w-full p-3 rounded-lg text-sm border ${themeClasses.bgInput} ${themeClasses.borderSecondary} ${themeClasses.textPrimary} focus:ring-2 focus:ring-sky-500 outline-none h-32 resize-none`}
                                        placeholder="Ví dụ: Một chú mèo phi hành gia đang lướt sóng trên dải ngân hà, phong cách cyberpunk..."
                                        value={createPrompt}
                                        onChange={(e) => setCreatePrompt(e.target.value)}
                                    />
                                    <button 
                                        type="button"
                                        onClick={handleOptimizePrompt}
                                        disabled={isOptimizingPrompt || !createPrompt.trim()}
                                        className="absolute bottom-2 right-2 flex items-center px-2 py-1 bg-gradient-to-r from-purple-500 to-pink-500 text-white rounded-md text-xs font-bold shadow-md hover:opacity-90 disabled:opacity-50 transition-all"
                                    >
                                        {isOptimizingPrompt ? <Spinner /> : <><SparklesIcon /> AI Viết lại</>}
                                    </button>
                                </div>
                            </div>

                            <div className="space-y-2">
                                <div className="flex justify-between items-center">
                                    <label className={`text-sm font-bold ${themeClasses.textSecondary}`}>Thinking Mode (Tư duy sâu)</label>
                                    <ToggleSwitch checked={createThinkingMode} onChange={setCreateThinkingMode} label="" themeClasses={themeClasses} />
                                </div>
                                <p className="text-[10px] text-gray-400">Bật tính năng này để AI suy nghĩ kỹ hơn về bố cục và chi tiết trước khi tối ưu prompt.</p>
                            </div>

                            <div className="grid grid-cols-2 gap-4">
                                <div className="space-y-2">
                                    <label className={`text-xs font-bold ${themeClasses.textSecondary}`}>Tỷ lệ khung hình</label>
                                    <select 
                                        className={`w-full p-2 rounded-md text-xs border ${themeClasses.bgInput} ${themeClasses.borderSecondary} ${themeClasses.textPrimary}`}
                                        value={createAspectRatio}
                                        onChange={(e) => setCreateAspectRatio(e.target.value as CreateAspectRatio)}
                                    >
                                        <option value="1:1">Vuông (1:1)</option>
                                        <option value="16:9">Ngang (16:9)</option>
                                        <option value="9:16">Dọc (9:16)</option>
                                        <option value="4:3">4:3</option>
                                        <option value="3:4">3:4</option>
                                        <option value="21:9">Điện ảnh (21:9)</option>
                                    </select>
                                </div>
                                <div className="space-y-2">
                                    <label className={`text-xs font-bold ${themeClasses.textSecondary}`}>Độ phân giải</label>
                                    <select 
                                        className={`w-full p-2 rounded-md text-xs border ${themeClasses.bgInput} ${themeClasses.borderSecondary} ${themeClasses.textPrimary}`}
                                        value={createSize}
                                        onChange={(e) => setCreateSize(e.target.value as CreateSize)}
                                    >
                                        <option value="1K">1K (Standard)</option>
                                        <option value="2K">2K (High Res)</option>
                                        <option value="4K">4K (Ultra Res)</option>
                                    </select>
                                </div>
                            </div>
                        </div>
                    )}
                </div>
            </div>

            {/* RIGHT COLUMN: IMAGES & ACTIONS & HISTORY */}
            <div className="lg:col-span-8 flex flex-col gap-6">

                {/* 1. Images Display Area */}
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4 items-start">

                    {/* Original Image Display (Hidden in Create Mode) */}
                    {mode !== 'create' && (
                        <div className="flex flex-col gap-3">
                            <div className="relative group">
                                 <ImageDisplay 
                                    title="Ảnh Gốc" 
                                    imageSrc={getOriginalImageSrc()} 
                                    placeholderText={mode === 'id' ? "Tải ảnh chân dung lên" : "Tải ảnh cũ cần phục hồi"}
                                    themeClasses={themeClasses}
                                 />
                                 {/* Floating Upload Button (Icon only) */}
                                 <label className="absolute top-4 right-4 p-2 bg-white/90 text-gray-800 rounded-full cursor-pointer shadow-lg hover:scale-110 transition-transform z-10" title="Tải ảnh lên">
                                    <UploadIcon />
                                    <input type="file" className="hidden" onChange={handleImageUpload} accept="image/*" />
                                 </label>
                            </div>

                            {/* Analysis Section (Moved OUTSIDE ImageDisplay) */}
                            {mode === 'id' && originalImage && (
                                <div className="w-full">
                                    {!analysisResult ? (
                                        <button 
                                            onClick={handleAnalyze}
                                            disabled={isAnalyzing}
                                            className={`w-full flex items-center justify-center py-2 rounded-lg border ${themeClasses.borderSecondary} ${themeClasses.bgSecondary} ${themeClasses.textSecondary} hover:${themeClasses.textPrimary} hover:border-sky-500 transition-all font-medium text-sm shadow-sm`}
                                        >
                                            {isAnalyzing ? <Spinner /> : <><AnalyzeIcon /> Phân tích nhanh chất lượng ảnh</>}
                                        </button>
                                    ) : (
                                        <div className="relative animate-fade-in-up">
                                            <AnalysisResultCard result={analysisResult} themeClasses={themeClasses} />
                                            <button 
                                                onClick={() => setAnalysisResult(null)} 
                                                className="absolute top-3 right-3 text-gray-400 hover:text-red-400 transition-colors"
                                                title="Đóng kết quả"
                                            >
                                                <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
                                                  <path fillRule="evenodd" d="M4.293 4.293a1 1 0 011.414 0L10 8.586l4.293-4.293a1 1 0 111.414 1.414L11.414 10l4.293 4.293a1 1 0 01-1.414 1.414L10 11.414l-4.293 4.293a1 1 0 01-1.414-1.414L8.586 10 4.293 5.707a1 1 0 010-1.414z" clipRule="evenodd" />
                                                </svg>
                                            </button>
                                        </div>
                                    )}
                                </div>
                            )}
