                    )}

                    {/* Result Image Display (Spans full width in Create Mode) */}
                    <div className={mode === 'create' ? "md:col-span-2" : ""}>
                        <div className="relative">
                            <ImageDisplay 
                                title="Kết quả AI" 
                                imageSrc={editedImage} 
                                isLoading={isLoading} 
                                placeholderText="Kết quả sẽ hiển thị tại đây..." 
                                themeClasses={themeClasses} 
                                downloadable={true}
                                downloadFilename={downloadFilename}
