                                        className={`p-2 rounded-full shadow-lg bg-white/90 text-gray-800 disabled:opacity-50 disabled:cursor-not-allowed hover:bg-white transition-all`}
                                        title="Hoàn tác"
                                    >
                                        <UndoIcon />
                                    </button>
                                    <button 
                                        onClick={handleRedo} 
                                        disabled={currentEditIndex >= editStack.length - 1}
                                        className={`p-2 rounded-full shadow-lg bg-white/90 text-gray-800 disabled:opacity-50 disabled:cursor-not-allowed hover:bg-white transition-all`}
                                        title="Làm lại"
                                    >
                                        <RedoIcon />
                                    </button>
                                </div>
                            )}
