import React, { useState, useRef } from 'react';
import ImageDisplay from './components/ImageDisplay';
import TextResultDisplay from './components/TextResultDisplay';
import Spinner from './components/Spinner';
import { fileToBase64 } from './utils/fileUtils';
import { ImageFile, IdAnalysisResult } from './types';
import { 
  editImageWithPrompt, 
  generateImage, 
  analyzeImageAttributes, 
  refinePromptWithThinking 
} from './services/geminiService';

const BrainIcon = () => (
  <svg xmlns="http://www.w3.org/2000/svg" className="h-3 w-3" fill="none" viewBox="0 0 24 24" stroke="currentColor">
    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9.663 17h4.673M12 3v1m6.364 1.636l-.707.707M21 12h-1M4 12H3m3.343-5.657l-.707-.707m2.828 9.9a5 5 0 117.072 0l-.548.547A3.374 3.374 0 0014 18.469V19a2 2 0 11-4 0v-.531c0-.895-.356-1.754-.988-2.386l-.548-.547z" />
  </svg>
);

const MagicWandIcon = () => (
  <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19.428 15.428a2 2 0 00-1.022-.547l-2.387-.477a6 6 0 00-3.86.517l-.318.158a6 6 0 01-3.86.517L6.05 15.21a2 2 0 00-1.806.547M8 4h8l-1 1v5.172a2 2 0 00.586 1.414l5 5c1.26 1.26.367 3.414-1.415 3.414H4.828c-1.782 0-2.674-2.154-1.414-3.414l5-5A2 2 0 009 10.172V5L8 4z" />
  </svg>
);

const UploadIcon = () => (
    <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8 text-gray-400" fill="none" viewBox="0 0 24 24" stroke="currentColor">
        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-8l-4-4m0 0L8 8m4-4v12" />
    </svg>
);

const App: React.FC = () => {
  const [mode, setMode] = useState<'id' | 'restore' | 'create'>('id');
  const [isLoading, setIsLoading] = useState(false);
  const [isOptimizingPrompt, setIsOptimizingPrompt] = useState(false);

  // Input State
  const [originalImage, setOriginalImage] = useState<ImageFile | null>(null);
  const [customPrompt, setCustomPrompt] = useState('');
  const [restoreCustomPrompt, setRestoreCustomPrompt] = useState('');
  const [createPrompt, setCreatePrompt] = useState('');

  // Output State
  const [resultImage, setResultImage] = useState<string | null>(null);
  const [analysisResult, setAnalysisResult] = useState<IdAnalysisResult | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);

  const themeClasses = {
    bgPrimary: 'bg-white',
    bgSecondary: 'bg-slate-50',
    bgInput: 'bg-white',
    textPrimary: 'text-slate-900',
    textSecondary: 'text-slate-500',
    accentText: 'text-blue-600',
    accentTextStrong: 'text-blue-700',
    accentTextHover: 'hover:text-blue-800',
    border: 'border-slate-200',
    borderSecondary: 'border-slate-300',
    button: {
        bg: 'bg-blue-600',
        hoverBg: 'hover:bg-blue-700',
        text: 'text-white'
    }
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      try {
        const base64 = await fileToBase64(file);
        setOriginalImage({
          base64,
          mimeType: file.type,
          name: file.name
        });
        setResultImage(null);
        setAnalysisResult(null);
      } catch (error) {
        console.error("File upload error:", error);
        alert("Lỗi tải ảnh lên.");
      }
    }
  };

  const handleOptimizePrompt = async () => {
    const currentPrompt = mode === 'id' ? customPrompt : restoreCustomPrompt;
    if (!currentPrompt.trim()) return;

    setIsOptimizingPrompt(true);
    try {
        const optimized = await refinePromptWithThinking(currentPrompt);
        if (mode === 'id') {
            setCustomPrompt(optimized);
        } else {
            setRestoreCustomPrompt(optimized);
        }
    } catch (error) {
        console.error("Optimization error:", error);
    } finally {
        setIsOptimizingPrompt(false);
    }
  };

  const handleSubmit = async () => {
    setIsLoading(true);
    setResultImage(null);
    setAnalysisResult(null);

    try {
        if (mode === 'create') {
            if (!createPrompt.trim()) return;
            const imgData = await generateImage(createPrompt);
            setResultImage(`data:image/png;base64,${imgData}`);
        } else {
            if (!originalImage) return;

            if (mode === 'id') {
                // Default prompt for ID photos
                const basePrompt = "Professional ID photo, white background, clear face, formal attire, 4x6 ratio style";
                const finalPrompt = customPrompt ? `${basePrompt}, ${customPrompt}` : basePrompt;

                const imgData = await editImageWithPrompt(originalImage, finalPrompt, 'gemini-2.5-flash-image');
                setResultImage(`data:image/png;base64,${imgData}`);

                // Analyze the original image for user feedback
                const analysis = await analyzeImageAttributes(originalImage);
                setAnalysisResult(analysis);

            } else if (mode === 'restore') {
                const basePrompt = "Restore this old photo, remove scratches, improve sharpness, colorize if black and white, high definition";
                const finalPrompt = restoreCustomPrompt ? `${basePrompt}, ${restoreCustomPrompt}` : basePrompt;

                // Using Pro model for better restoration results if available
                const imgData = await editImageWithPrompt(originalImage, finalPrompt, 'gemini-3-pro-image-preview');
                setResultImage(`data:image/png;base64,${imgData}`);
            }
        }
    } catch (error: any) {
