                const prompt = "Restore this old or damaged photo to high quality. Remove scratches, dust, noise, and blur. Sharpen facial details, enhance textures, and correct color balance to make it look like a modern high-resolution photograph.";
                imageBase64 = await editImageWithPrompt(originalImage, prompt);
