                                        className={`w-full h-48 p-4 rounded-xl bg-gray-900 border ${themeClasses.borderSecondary} focus:border-blue-500 focus:ring-2 focus:ring-blue-500/20 outline-none transition-all resize-none text-base leading-relaxed`}
