    };

    const handleSubmit = async () => {
        setIsLoading(true);
        setResultImage(null);

        try {
            let resultBase64 = '';

            if (mode === 'create') {
                if (!createPrompt.trim()) return;
                resultBase64 = await generateImage(createPrompt);

                const dataUrl = `data:image/png;base64,${resultBase64}`;
                setResultImage(dataUrl);

                setCreateHistory(prev => [{
                    edited: dataUrl,
                    prompt: createPrompt,
                    timestamp: Date.now()
                }, ...prev]);

            } else {
                if (!selectedImage) return;

                let prompt = "";
                // Define specialized prompts based on mode
                if (mode === 'id') {
                    prompt = "Biến ảnh này thành ảnh thẻ chuyên nghiệp, phông nền xanh dương hoặc trắng (tuỳ chọn tốt nhất), mặt nhìn thẳng, sáng sủa, rõ nét, tỉ lệ chuẩn.";
                } else if (mode === 'restore') {
                    prompt = "Khôi phục ảnh cũ này, làm nét, khử nhiễu, tăng độ chi tiết, làm màu sắc tươi tắn hơn.";
                }

                resultBase64 = await editImageWithPrompt(selectedImage, prompt);
                const dataUrl = `data:image/png;base64,${resultBase64}`;
                setResultImage(dataUrl);

                const newItem: HistoryItem = {
                    original: selectedImage,
                    edited: dataUrl,
                    prompt: prompt,
                    timestamp: Date.now()
                };

                if (mode === 'id') setIdHistory(prev => [newItem, ...prev]);
                else setRestoreHistory(prev => [newItem, ...prev]);
            }

        } catch (error: any) {
            console.error(error);
            alert("Lỗi xử lý: " + (error.message || "Đã có lỗi xảy ra"));
        } finally {
            setIsLoading(false);
        }
    };

    const triggerFileInput = () => {
        fileInputRef.current?.click();
    };

    return (
        <div className={`min-h-screen ${themeClasses.bgPrimary} ${themeClasses.textPrimary} font-sans p-4 md:p-8`}>
            {/* Header */}
            <div className="max-w-7xl mx-auto mb-8 text-center">
                <h1 className="text-3xl md:text-5xl font-extrabold tracking-tight mb-2">
                    <span className="text-transparent bg-clip-text bg-gradient-to-r from-sky-400 to-blue-600">Gemini</span> Photo AI
                </h1>
                <p className={`${themeClasses.textSecondary} text-sm md:text-base`}>Công cụ chỉnh sửa và tạo ảnh thông minh</p>
            </div>

            {/* Mode Switcher */}
            <div className="max-w-4xl mx-auto mb-8 flex flex-wrap justify-center gap-2 p-1 bg-slate-800/50 rounded-xl backdrop-blur-sm border border-slate-700/50">
                {(['id', 'restore', 'create'] as const).map((m) => (
                    <button
                        key={m}
                        onClick={() => { setMode(m); setSelectedImage(null); setResultImage(null); }}
                        className={`px-6 py-2.5 rounded-lg text-sm font-semibold transition-all duration-200 capitalize ${
                            mode === m 
                            ? 'bg-sky-600 text-white shadow-lg shadow-sky-900/50' 
                            : 'text-slate-400 hover:text-white hover:bg-slate-700'
                        }`}
                    >
                        {m === 'id' ? 'Ảnh Thẻ' : m === 'restore' ? 'Phục Chế' : 'Sáng Tạo'}
                    </button>
                ))}
            </div>

            {/* Main Content */}
            <div className="max-w-7xl mx-auto grid grid-cols-1 lg:grid-cols-12 gap-8">

                {/* Left Column: Input */}
                <div className="lg:col-span-5 flex flex-col space-y-6">
                    <div className={`${themeClasses.bgSecondary} rounded-xl shadow-xl p-6 border ${themeClasses.border}`}>
                        <h2 className={`text-xl font-bold ${themeClasses.accentText} mb-4 flex items-center`}>
                            {mode === 'create' ? 'Nhập Mô Tả' : 'Tải Ảnh Lên'}
                        </h2>

                        {mode === 'create' ? (
                            <div className="space-y-4">
                                <textarea
                                    value={createPrompt}
                                    onChange={(e) => setCreatePrompt(e.target.value)}
                                    placeholder="Mô tả chi tiết bức ảnh bạn muốn tạo..."
                                    className={`w-full h-48 bg-slate-900/50 border ${themeClasses.borderSecondary} rounded-xl p-4 text-slate-200 focus:ring-2 focus:ring-sky-500 focus:border-transparent outline-none resize-none transition-all`}
                                />
                            </div>
                        ) : (
                            <div 
                                onClick={triggerFileInput}
                                className={`w-full h-64 border-2 border-dashed ${selectedImage ? 'border-sky-500 bg-sky-900/10' : 'border-slate-600 hover:border-sky-500 hover:bg-slate-700/30'} rounded-xl flex flex-col items-center justify-center cursor-pointer transition-all group relative overflow-hidden`}
                            >
                                {selectedImage ? (
                                    <>
                                        <img src={`data:${selectedImage.mimeType};base64,${selectedImage.base64}`} alt="Preview" className="h-full w-full object-contain p-2" />
                                        <div className="absolute inset-0 bg-black/50 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity">
                                            <p className="text-white font-medium flex items-center"><UploadIcon /> Thay đổi</p>
                                        </div>
                                    </>
                                ) : (
                                    <>
                                        <UploadIcon />
                                        <p className="text-slate-400 group-hover:text-slate-200 font-medium">Nhấn để tải ảnh lên</p>
                                        <p className="text-slate-500 text-xs mt-2">JPG, PNG (Max 5MB)</p>
                                    </>
                                )}
                                <input 
                                    type="file" 
                                    ref={fileInputRef} 
                                    className="hidden" 
                                    accept="image/*" 
                                    onChange={handleFileChange} 
                                />
                            </div>
                        )}

                        {/* Action Button for ID/Restore */}
                        {mode !== 'create' && (
                             <button
                                onClick={handleSubmit}
                                disabled={isLoading || !selectedImage}
                                className={`mt-6 w-full py-3.5 rounded-xl font-bold text-lg shadow-lg transform transition-all active:scale-95 disabled:opacity-50 disabled:cursor-not-allowed ${themeClasses.button.bg} ${themeClasses.button.text} ${themeClasses.button.hoverBg} flex items-center justify-center space-x-2`}
                            >
                                {isLoading ? <Spinner /> : <MagicWandIcon />}
                                <span>{isLoading ? 'Đang Xử Lý...' : (mode === 'id' ? 'Tạo Ảnh Thẻ' : 'Phục Chế Ảnh')}</span>
                            </button>
                        )}
                    </div>
                </div>

                {/* Right Column: Result & History */}
                <div className="lg:col-span-7 flex flex-col space-y-6">

                    {/* Main Display */}
                    <ImageDisplay 
                        title={mode === 'create' ? "Kết Quả Sáng Tạo" : (mode === 'id' ? "Ảnh Thẻ Hoàn Thiện" : "Ảnh Phục Chế")}
                        imageSrc={resultImage}
                        isLoading={isLoading}
                        placeholderText={mode === 'create' ? "Ảnh được tạo sẽ xuất hiện tại đây" : "Kết quả xử lý sẽ xuất hiện tại đây"}
                        themeClasses={themeClasses}
                        downloadable={true}
                    />

                    {/* History Section */}
                    <div className="flex space-x-4 overflow-x-auto pb-4 scrollbar-hide snap-x">
                        {(mode === 'id' ? idHistory : mode === 'restore' ? restoreHistory : createHistory).map((item, index) => (
                            <div 
                                key={index} 
                                onClick={() => handleHistoryClick(item)}
                                className={`flex-shrink-0 w-64 snap-start cursor-pointer group relative rounded-lg overflow-hidden border ${themeClasses.borderSecondary} hover:border-sky-500 transition-all shadow-md`}
                            >
                                {/* Split view for ID/Restore */}
                                {mode !== 'create' && item.original ? (
                                    <div className="flex h-40 w-full">
                                        <div className="w-1/2 relative border-r border-white/10">
                                            <img src={`data:${item.original.mimeType};base64,${item.original.base64}`} className="w-full h-full object-cover" alt="Original" />
                                            <span className="absolute bottom-1 left-1 text-[9px] bg-black/60 text-white px-1 rounded">Gốc</span>
                                        </div>
                                        <div className="w-1/2 relative">
                                            <img src={item.edited} className="w-full h-full object-cover" alt="Edited" />
                                            <span className="absolute bottom-1 right-1 text-[9px] bg-sky-600/80 text-white px-1 rounded">Mới</span>
                                        </div>
                                    </div>
                                ) : (
                                    // Full view for Create Mode
                                    <div className="h-40 w-full relative">
                                        <img src={item.edited} className="w-full h-full object-cover" alt="Created" />
                                        <p className="absolute bottom-0 w-full bg-black/70 text-white text-[10px] p-1 truncate">{item.prompt}</p>
                                    </div>
                                )}

                                {/* Hover Overlay */}
                                <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center">
                                    <span className="px-3 py-1 bg-white/20 backdrop-blur-md text-white text-xs rounded-full font-medium border border-white/30">Xem lại</span>
                                </div>
                            </div>
                        ))}
                        {(mode === 'id' ? idHistory : mode === 'restore' ? restoreHistory : createHistory).length === 0 && (
                            <div className={`w-full py-8 text-center text-sm ${themeClasses.textSecondary} italic`}>
                                Chưa có lịch sử nào.
                            </div>
                        )}
                    </div>

                    {/* Create Mode Action Button (Restored below History) */}
                    {mode === 'create' && (
                        <button
                            onClick={handleSubmit}
                            disabled={isLoading || !createPrompt.trim()}
                            className={`w-full py-4 rounded-xl font-bold text-lg shadow-lg transform transition-all active:scale-95 disabled:opacity-50 disabled:cursor-not-allowed ${themeClasses.button.bg} ${themeClasses.button.text} ${themeClasses.button.hoverBg} flex items-center justify-center space-x-2`}
                        >
                            {isLoading ? (
                                <><Spinner /> <span>Đang sáng tạo...</span></>
                            ) : (
                                <><MagicWandIcon /> <span>Tạo Ảnh Ngay</span></>
                            )}
                        </button>
                    )}

                </div>
            </div>
        </div>
    );
};

export default App;

