import React, { useState, useRef } from 'react';
import ImageDisplay from './components/ImageDisplay';
import Spinner from './components/Spinner';
import { fileToBase64 } from './utils/fileUtils';
import { generateImage, editImageWithPrompt, analyzeImageAttributes } from './services/geminiService';
import { ImageFile, IdAnalysisResult } from './types';

// Icons
const MagicWandIcon = () => (
  <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
    <path strokeLinecap="round" strokeLinejoin="round" d="M19.428 15.428a2 2 0 00-1.022-.547l-2.387-.477a6 6 0 00-3.86.517l-.318.158a6 6 0 01-3.86.517L6.05 15.21a2 2 0 00-1.806.547M8 4h8l-1 1v5.172a2 2 0 00.586 1.414l5 5c1.26 1.26.367 3.414-1.415 3.414H4.828c-1.782 0-2.674-2.154-1.414-3.414l5-5A2 2 0 009 10.172V5L8 4z" />
  </svg>
);

const PhotoIcon = () => (
  <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
    <path strokeLinecap="round" strokeLinejoin="round" d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" />
  </svg>
);

const IDCardIcon = () => (
    <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
      <path strokeLinecap="round" strokeLinejoin="round" d="M10 6H5a2 2 0 00-2 2v9a2 2 0 002 2h14a2 2 0 002-2V8a2 2 0 00-2-2h-5m-4 0V5a2 2 0 114 0v1m-4 0a2 2 0 104 0m-5 8a2 2 0 100-4 2 2 0 000 4zm0 0c1.306 0 2.417.835 2.83 2M9 14a3.001 3.001 0 00-2.83 2M15 11h3m-3 4h2" />
    </svg>
);

// Types
type Tab = 'create' | 'edit' | 'id';
type CreateSize = '1K' | '2K' | '4K';

const App: React.FC = () => {
    const [activeTab, setActiveTab] = useState<Tab>('create');
    const [isLoading, setIsLoading] = useState(false);

    // Create State
    const [createPrompt, setCreatePrompt] = useState('');
    const [createAspectRatio, setCreateAspectRatio] = useState('1:1');
    const [createSize, setCreateSize] = useState<CreateSize>('1K');

    // Edit State
    const [editPrompt, setEditPrompt] = useState('');
    const [editImage, setEditImage] = useState<ImageFile | null>(null);

    // ID State
    const [idImage, setIdImage] = useState<ImageFile | null>(null);
    const [idAnalysis, setIdAnalysis] = useState<IdAnalysisResult | null>(null);

    // Results
    const [resultImage, setResultImage] = useState<string | null>(null);
    const [error, setError] = useState<string | null>(null);

    const fileInputRef = useRef<HTMLInputElement>(null);

    const themeClasses = {
        bgApp: 'bg-slate-900',
        bgPrimary: 'bg-slate-800',
        bgSecondary: 'bg-slate-700',
        bgInput: 'bg-slate-600',
        textPrimary: 'text-white',
        textSecondary: 'text-slate-300',
        accentText: 'text-cyan-400',
        accentTextStrong: 'text-cyan-300',
        accentTextHover: 'hover:text-cyan-200',
        border: 'border-slate-600',
        borderSecondary: 'border-slate-500',
        button: {
            bg: 'bg-gradient-to-r from-cyan-600 to-blue-600',
            hoverBg: 'hover:from-cyan-500 hover:to-blue-500',
            text: 'text-white',
        }
    };

    const handleFileChange = async (event: React.ChangeEvent<HTMLInputElement>, type: 'edit' | 'id') => {
        if (event.target.files && event.target.files[0]) {
            const file = event.target.files[0];
            try {
                const base64 = await fileToBase64(file);
                const imageFile: ImageFile = {
                    base64,
                    mimeType: file.type,
                    name: file.name
                };
                if (type === 'edit') setEditImage(imageFile);
                else setIdImage(imageFile);

                // Reset results
                setResultImage(null);
                setIdAnalysis(null);
                setError(null);
            } catch (e) {
                setError("Error reading file");
            }
        }
    };

    const handleSubmit = async () => {
        setIsLoading(true);
        setError(null);
        setResultImage(null);
        setIdAnalysis(null);

        try {
            if (activeTab === 'create') {
                const result = await generateImage(createPrompt, createAspectRatio, createSize);
                const mimeType = createSize === '1K' ? 'image/jpeg' : 'image/png';
                setResultImage(`data:${mimeType};base64,${result}`);
            } else if (activeTab === 'edit') {
                if (!editImage) throw new Error("Please select an image");
                const result = await editImageWithPrompt(editImage, editPrompt, 'gemini-2.5-flash-image');
                setResultImage(`data:image/jpeg;base64,${result}`);
            } else if (activeTab === 'id') {
                if (!idImage) throw new Error("Please select an ID photo");
                const result = await analyzeImageAttributes(idImage);
                setIdAnalysis(result);
            }
        } catch (err: any) {
            setError(err.message || "An error occurred");
        } finally {
            setIsLoading(false);
        }
    };

    const renderTabContent = () => {
        switch (activeTab) {
            case 'create':
                return (
                    <div className="space-y-4">
                        <div>
                            <label className={`block text-sm font-medium ${themeClasses.textSecondary} mb-1`}>Mô tả hình ảnh</label>
                            <textarea 
                                className={`w-full p-3 rounded-lg ${themeClasses.bgInput} ${themeClasses.textPrimary} border ${themeClasses.border} focus:ring-2 focus:ring-cyan-500 outline-none`}
                                rows={4}
                                placeholder="Một chú mèo máy màu xanh đang ăn bánh rán..."
                                value={createPrompt}
                                onChange={(e) => setCreatePrompt(e.target.value)}
                            />
                        </div>
                        <div className="grid grid-cols-2 gap-4">
                            <div>
                                <label className={`block text-sm font-medium ${themeClasses.textSecondary} mb-1`}>Tỉ lệ khung hình</label>
                                <select 
                                    className={`w-full p-2 rounded-md ${themeClasses.bgInput} ${themeClasses.textPrimary} border ${themeClasses.border}`}
