    const [createSize, setCreateSize] = useState<CreateSize>('1K');

    // Edit State
    const [editPrompt, setEditPrompt] = useState('');
    const [editImage, setEditImage] = useState<ImageFile | null>(null);

    // ID State
    const [idImage, setIdImage] = useState<ImageFile | null>(null);
    const [idAnalysis, setIdAnalysis] = useState<IdAnalysisResult | null>(null);

    // Results
    const [resultImage, setResultImage] = useState<string | null>(null);
    const [error, setError] = useState<string | null>(null);

    const fileInputRef = useRef<HTMLInputElement>(null);

    const themeClasses = {
        bgApp: 'bg-slate-900',
        bgPrimary: 'bg-slate-900', // Adjusted to match ImageDisplay expectations
        bgSecondary: 'bg-slate-800',
        bgInput: 'bg-slate-700',
        textPrimary: 'text-slate-100',
        textSecondary: 'text-slate-400',
        accentText: 'text-cyan-400',
        accentTextStrong: 'text-cyan-300',
        accentTextHover: 'hover:text-cyan-200',
        border: 'border-slate-700',
        borderSecondary: 'border-slate-600',
        button: {
            bg: 'bg-gradient-to-r from-cyan-600 to-blue-600',
            hoverBg: 'hover:from-cyan-500 hover:to-blue-500',
            text: 'text-white',
        }
    };

    const handleFileChange = async (event: React.ChangeEvent<HTMLInputElement>, type: 'edit' | 'id') => {
        if (event.target.files && event.target.files[0]) {
            const file = event.target.files[0];
            try {
                const base64 = await fileToBase64(file);
                const imageFile: ImageFile = {
                    base64,
                    mimeType: file.type,
                    name: file.name
                };
                if (type === 'edit') setEditImage(imageFile);
                else setIdImage(imageFile);

                // Reset results when new file is loaded
                if (type === 'id') setIdAnalysis(null);
                setResultImage(null);
                setError(null);
            } catch (e) {
                setError("Lỗi khi đọc file. Vui lòng thử lại.");
            }
        }
    };

    const handleSubmit = async () => {
        setIsLoading(true);
        setError(null);

        // Only clear result if we are in create mode or submitting a new request
        if (activeTab === 'create') setResultImage(null);
        if (activeTab === 'id') setIdAnalysis(null);

        try {
            if (activeTab === 'create') {
                const result = await generateImage(createPrompt, createAspectRatio, createSize);
                const mimeType = createSize === '1K' ? 'image/jpeg' : 'image/png';
                setResultImage(`data:${mimeType};base64,${result}`);
            } else if (activeTab === 'edit') {
                if (!editImage) throw new Error("Vui lòng chọn ảnh cần chỉnh sửa.");
                if (!editPrompt.trim()) throw new Error("Vui lòng nhập yêu cầu chỉnh sửa.");

                // Use Pro model for editing if user implicitly wants high quality, otherwise default logic in service
                const result = await editImageWithPrompt(editImage, editPrompt, 'gemini-2.5-flash-image');
                setResultImage(`data:image/jpeg;base64,${result}`);
            } else if (activeTab === 'id') {
                if (!idImage) throw new Error("Vui lòng chọn ảnh thẻ.");
                const result = await analyzeImageAttributes(idImage);
                setIdAnalysis(result);
            }
        } catch (err: any) {
            setError(err.message || "Đã xảy ra lỗi không xác định.");
        } finally {
            setIsLoading(false);
        }
    };

    const renderTabContent = () => {
        switch (activeTab) {
            case 'create':
                return (
                    <div className="space-y-4 animate-fade-in">
                        <div>
                            <label className={`block text-xs font-bold uppercase tracking-wider ${themeClasses.textSecondary} mb-2`}>Mô tả hình ảnh</label>
                            <textarea 
                                className={`w-full p-3 rounded-xl ${themeClasses.bgInput} ${themeClasses.textPrimary} border ${themeClasses.borderSecondary} focus:ring-2 focus:ring-cyan-500 outline-none transition-all`}
                                rows={4}
                                placeholder="Một chú mèo máy màu xanh đang ăn bánh rán trên mặt trăng..."
                                value={createPrompt}
                                onChange={(e) => setCreatePrompt(e.target.value)}
                            />
                        </div>
                        <div className="grid grid-cols-2 gap-4">
                            <div>
                                <label className={`block text-xs font-bold uppercase tracking-wider ${themeClasses.textSecondary} mb-2`}>Tỉ lệ</label>
                                <select 
                                    className={`w-full p-2.5 rounded-lg ${themeClasses.bgInput} ${themeClasses.textPrimary} border ${themeClasses.borderSecondary} focus:ring-2 focus:ring-cyan-500 outline-none`}
                                    value={createAspectRatio}
                                    onChange={(e) => setCreateAspectRatio(e.target.value)}
                                >
                                    <option value="1:1">1:1 (Vuông)</option>
                                    <option value="16:9">16:9 (Ngang)</option>
                                    <option value="9:16">9:16 (Dọc)</option>
                                    <option value="3:4">3:4 (Chân dung)</option>
                                    <option value="4:3">4:3 (Cổ điển)</option>
                                </select>
                            </div>
                            <div>
                                <label className={`block text-xs font-bold uppercase tracking-wider ${themeClasses.textSecondary} mb-2`}>Chất lượng</label>
                                <select 
                                    className={`w-full p-2.5 rounded-lg ${themeClasses.bgInput} ${themeClasses.textPrimary} border ${themeClasses.borderSecondary} focus:ring-2 focus:ring-cyan-500 outline-none`}
                                    value={createSize}
                                    onChange={(e) => setCreateSize(e.target.value as CreateSize)}
                                >
                                    <option value="1K">1K (Tiêu chuẩn)</option>
                                    <option value="2K">2K (Cao cấp)</option>
                                    <option value="4K">4K (Siêu nét)</option>
                                </select>
                            </div>
                        </div>
                    </div>
                );
            case 'edit':
                return (
                    <div className="space-y-4 animate-fade-in">
                        <div 
                            className={`border-2 border-dashed ${themeClasses.borderSecondary} rounded-xl p-6 flex flex-col items-center justify-center cursor-pointer hover:bg-slate-700/50 transition-colors group relative overflow-hidden`}
                            onClick={() => fileInputRef.current?.click()}
                        >
                            {editImage ? (
                                <div className="text-center w-full relative z-10">
                                    <p className={`${themeClasses.accentText} font-medium truncate max-w-full px-4`}>{editImage.name}</p>
                                    <p className="text-xs text-gray-400 mt-1">Nhấn để thay đổi ảnh</p>
                                </div>
                            ) : (
                                <div className="text-center group-hover:scale-105 transition-transform duration-300">
                                    <UploadIcon />
                                    <span className={`mt-2 block text-sm ${themeClasses.textSecondary}`}>Tải ảnh lên để chỉnh sửa</span>
                                </div>
                            )}
                            {editImage && (
                                <img 
                                    src={`data:${editImage.mimeType};base64,${editImage.base64}`} 
                                    className="absolute inset-0 w-full h-full object-cover opacity-20 blur-sm"
                                    alt="Preview"
                                />
                            )}
                            <input 
                                type="file" 
                                ref={fileInputRef} 
                                className="hidden" 
                                accept="image/*"
                                onChange={(e) => handleFileChange(e, 'edit')}
                            />
                        </div>
                        <div>
                            <label className={`block text-xs font-bold uppercase tracking-wider ${themeClasses.textSecondary} mb-2`}>Yêu cầu chỉnh sửa</label>
                            <textarea 
                                className={`w-full p-3 rounded-xl ${themeClasses.bgInput} ${themeClasses.textPrimary} border ${themeClasses.borderSecondary} focus:ring-2 focus:ring-cyan-500 outline-none`}
                                rows={3}
                                placeholder="Thay áo vest đen, thêm cà vạt đỏ, xóa phông nền..."
                                value={editPrompt}
                                onChange={(e) => setEditPrompt(e.target.value)}
                            />
                        </div>
                    </div>
                );
            case 'id':
                return (
                    <div className="space-y-4 animate-fade-in">
                         <div 
                            className={`border-2 border-dashed ${themeClasses.borderSecondary} rounded-xl p-6 flex flex-col items-center justify-center cursor-pointer hover:bg-slate-700/50 transition-colors group relative overflow-hidden`}
                            onClick={() => fileInputRef.current?.click()}
                        >
                            {idImage ? (
                                <div className="text-center relative z-10">
                                    <p className={`${themeClasses.accentText} font-medium truncate max-w-full px-4`}>{idImage.name}</p>
                                    <p className="text-xs text-gray-400 mt-1">Nhấn để thay đổi ảnh</p>
                                </div>
                            ) : (
                                <div className="text-center group-hover:scale-105 transition-transform duration-300">
                                    <UploadIcon />
                                    <span className={`mt-2 block text-sm ${themeClasses.textSecondary}`}>Tải ảnh chân dung/thẻ</span>
                                </div>
                            )}
                             {idImage && (
                                <img 
                                    src={`data:${idImage.mimeType};base64,${idImage.base64}`} 
                                    className="absolute inset-0 w-full h-full object-cover opacity-20 blur-sm"
                                    alt="Preview"
                                />
                            )}
                            <input 
                                type="file" 
                                ref={fileInputRef} 
                                className="hidden" 
                                accept="image/*"
                                onChange={(e) => handleFileChange(e, 'id')}
                            />
                        </div>
                        <div className={`p-4 rounded-lg bg-blue-900/20 border border-blue-800/50 text-sm ${themeClasses.textSecondary}`}>
                            <h4 className="font-semibold text-blue-300 mb-1 flex items-center">
                                <span className="mr-2">ℹ️</span> Tính năng AI:
                            </h4>
                            <ul className="list-disc list-inside space-y-1 opacity-80 text-xs ml-1">
                                <li>Kiểm tra góc mặt, ánh sáng, phông nền</li>
                                <li>Đánh giá độ sắc nét và nhiễu hạt</li>
                                <li>Đề xuất cải thiện để đạt chuẩn ảnh thẻ</li>
                            </ul>
                        </div>
                    </div>
                );
        }
    };

    return (
        <div className={`min-h-screen ${themeClasses.bgApp} ${themeClasses.textPrimary} font-sans selection:bg-cyan-500/30 selection:text-cyan-100`}>
            <div className="container mx-auto px-4 py-8 max-w-6xl">
                <header className="mb-10 text-center space-y-2">
                    <h1 className="text-3xl md:text-5xl font-extrabold bg-clip-text text-transparent bg-gradient-to-r from-cyan-400 via-blue-500 to-purple-500">
                        Studio Ảnh Nguyễn Quang
                    </h1>
                    <p className={`${themeClasses.textSecondary} text-lg font-light tracking-wide`}>
                        Công nghệ AI: Sáng tạo • Chỉnh sửa • Chuẩn hóa
                    </p>
                </header>

                <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
                    {/* Controls Panel */}
                    <div className="lg:col-span-4 space-y-6">
                        <div className={`${themeClasses.bgSecondary} rounded-2xl shadow-xl p-6 border ${themeClasses.border}`}>
                            {/* Tabs */}
                            <div className="flex space-x-1 mb-6 bg-slate-900/50 p-1 rounded-xl border border-slate-700/50">
                                {[
                                    { id: 'create', icon: MagicWandIcon, label: 'Tạo Ảnh' },
                                    { id: 'edit', icon: PhotoIcon, label: 'Chỉnh Sửa' },
                                    { id: 'id', icon: IDCardIcon, label: 'Ảnh Thẻ' },
                                ].map((tab) => (
                                    <button
                                        key={tab.id}
                                        onClick={() => {
                                            setActiveTab(tab.id as Tab);
                                            setError(null);
                                            // Don't clear images immediately to allow switching back comfortably, 
                                            // only clear results if needed or on new submission.
                                        }}
                                        className={`flex-1 flex items-center justify-center space-x-2 py-2.5 rounded-lg text-sm font-medium transition-all duration-200 ${
                                            activeTab === tab.id 
                                            ? 'bg-slate-700 text-cyan-300 shadow-md ring-1 ring-slate-600' 
                                            : 'text-slate-400 hover:text-slate-200 hover:bg-slate-800'
                                        }`}
                                    >
                                        <tab.icon />
                                        <span className="hidden sm:inline">{tab.label}</span>
                                    </button>
                                ))}
                            </div>

                            {/* Tab Content */}
                            {renderTabContent()}

                            {/* Error Message */}
                            {error && (
                                <div className="mt-4 p-3 bg-red-900/30 border border-red-800 rounded-xl text-red-200 text-sm animate-pulse">
                                    <strong>Lỗi:</strong> {error}
                                </div>
                            )}

                            {/* Action Button */}
                            <button
                                onClick={handleSubmit}
                                disabled={isLoading || (activeTab === 'create' && !createPrompt) || (activeTab === 'edit' && (!editImage || !editPrompt)) || (activeTab === 'id' && !idImage)}
                                className={`w-full mt-6 py-3.5 rounded-xl font-bold text-lg shadow-lg transform transition-all active:scale-[0.98] disabled:opacity-50 disabled:cursor-not-allowed ${themeClasses.button.bg} ${themeClasses.button.text} ${themeClasses.button.hoverBg} flex items-center justify-center space-x-2 group`}
                            >
                                {isLoading ? (
                                    <><Spinner /> <span>Đang xử lý...</span></>
                                ) : (
                                    <>
                                        <span className="group-hover:animate-bounce">
                                            {activeTab === 'create' ? <MagicWandIcon /> : activeTab === 'edit' ? <PhotoIcon /> : <IDCardIcon />}
                                        </span>
                                        <span>
                                            {activeTab === 'create' ? 'Tạo Ảnh Ngay' : activeTab === 'edit' ? 'Thực Hiện' : 'Phân Tích'}
                                        </span>
                                    </>
                                )}
                            </button>
                        </div>
                    </div>

                    {/* Results Panel */}
                    <div className="lg:col-span-8 flex flex-col gap-6">
                        {activeTab === 'id' && idAnalysis ? (
                            <div className="space-y-6 animate-fade-in">
                                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                                    <ImageDisplay 
                                        title="Ảnh gốc" 
                                        imageSrc={idImage ? `data:${idImage.mimeType};base64,${idImage.base64}` : null} 
                                        placeholderText="Ảnh sẽ hiển thị ở đây"
                                        themeClasses={themeClasses}
                                    />
                                    <div className={`${themeClasses.bgSecondary} rounded-xl shadow-lg p-6 border ${themeClasses.border} h-full`}>
                                        <div className="flex justify-between items-center mb-6 border-b border-slate-700 pb-4">
                                            <h2 className={`text-xl font-bold ${themeClasses.accentText}`}>Kết Quả Phân Tích</h2>
                                            <span className={`px-4 py-1.5 rounded-full text-sm font-bold shadow-sm ${idAnalysis.overallPass ? 'bg-green-500/20 text-green-400 border border-green-500/50' : 'bg-red-500/20 text-red-400 border border-red-500/50'}`}>
                                                {idAnalysis.overallPass ? 'ĐẠT TIÊU CHUẨN' : 'CẦN ĐIỀU CHỈNH'}
                                            </span>
                                        </div>

                                        <div className="space-y-5">
                                            <div className="grid grid-cols-2 gap-4 text-sm mb-4">
                                                <div className="p-3 bg-slate-900/50 rounded-lg border border-slate-700/50">
                                                    <div className="text-slate-400 text-xs uppercase font-bold tracking-wider mb-1">Giới tính</div>
                                                    <div className="font-semibold text-lg text-slate-200">{idAnalysis.gender}</div>
                                                </div>
                                                <div className="p-3 bg-slate-900/50 rounded-lg border border-slate-700/50">
                                                    <div className="text-slate-400 text-xs uppercase font-bold tracking-wider mb-1">Độ tuổi</div>
                                                    <div className="font-semibold text-lg text-slate-200">{idAnalysis.ageRange}</div>
                                                </div>
                                            </div>

                                            <div className="space-y-3">
                                                <AnalysisItem label="Phông nền" passed={idAnalysis.background.isClean} desc={idAnalysis.background.description} />
                                                <AnalysisItem label="Ánh sáng" passed={idAnalysis.lighting.isEven} desc={idAnalysis.lighting.description} />
                                                <AnalysisItem label="Khuôn mặt" passed={idAnalysis.face.isClear && idAnalysis.face.isStraight} desc={idAnalysis.face.description} />
                                                <AnalysisItem label="Chất lượng ảnh" passed={idAnalysis.quality.isSharp && !idAnalysis.quality.hasNoise} desc={idAnalysis.quality.description} />
                                            </div>
                                        </div>
                                    </div>
                                </div>
                            </div>
                        ) : (
                            <ImageDisplay 
                                title={activeTab === 'create' ? "Kết quả sáng tạo" : activeTab === 'edit' ? "Kết quả chỉnh sửa" : "Ảnh phân tích"}
                                imageSrc={resultImage || (activeTab === 'id' && idImage ? `data:${idImage.mimeType};base64,${idImage.base64}` : null)}
                                isLoading={isLoading}
                                placeholderText={isLoading ? "Đang xử lý..." : (activeTab === 'id' ? "Ảnh của bạn sẽ hiển thị tại đây" : "Kết quả sẽ xuất hiện tại đây")}
                                themeClasses={themeClasses}
                                downloadable={!!resultImage}
                                downloadFilename={`gemini-${activeTab}-${Date.now()}.png`}
                            />
                        )}
                    </div>
                </div>
            </div>
        </div>
    );
};

const AnalysisItem = ({ label, passed, desc }: { label: string, passed: boolean, desc: string }) => (
    <div className={`flex items-start space-x-3 p-3 rounded-lg border transition-all ${passed ? 'bg-green-900/10 border-green-900/30' : 'bg-red-900/10 border-red-900/30'}`}>
        <div className={`mt-0.5 flex-shrink-0 w-5 h-5 rounded-full flex items-center justify-center ${passed ? 'bg-green-500' : 'bg-red-500'}`}>
            {passed ? (
                <svg className="w-3 h-3 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M5 13l4 4L19 7"></path></svg>
            ) : (
                <svg className="w-3 h-3 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M6 18L18 6M6 6l12 12"></path></svg>
            )}
        </div>
        <div className="flex-1">
            <div className={`text-sm font-bold ${passed ? 'text-green-400' : 'text-red-400'}`}>{label}</div>
            <div className="text-xs text-slate-300 mt-0.5 leading-relaxed">{desc}</div>
        </div>
    </div>
);

export default App;

