  const [customBackgroundImage, setCustomBackgroundImage] = useState<ImageFile | null>(null);

  // Undo/Redo State
  const [editStack, setEditStack] = useState<string[]>([]);
  const [currentEditIndex, setCurrentEditIndex] = useState(-1);

