      });
  };

  const handleImageUpload = useCallback(async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    if (!file.type.startsWith('image/')) {
        setError('Vui lòng tải lên một tệp ảnh hợp lệ (PNG, JPG, etc.).');
        return;
    }

    setError(null);
    setEditedImage(null);
    setEditStack([]);
    setCurrentEditIndex(-1);
    setAnalysisResult(null);

    try {
        const base64 = await fileToBase64(file);
        const newImage = { base64, mimeType: file.type, name: file.name };
        setOriginalImage(newImage);

        // --- AUTO ANALYSIS START ---
        // Automatically run analysis to detect gender
        if (mode === 'id') {
            setIsAnalyzing(true);
            try {
                // Call analysis service
                const result = await analyzeImageAttributes(newImage);
                setAnalysisResult(result);

                // Auto switch gender tab based on result
                // SAFETY: Added optional chaining and empty string fallback
                const gender = result?.gender?.toLowerCase() || '';

                if (gender.includes('nam') || gender.includes('male')) {
                     setIdOptions(prev => ({
                         ...prev,
                         gender: 'male',
                         clothing: null, // Reset clothing when auto-switching
                         hairStyle: null
                     }));
                } else if (gender.includes('nữ') || gender.includes('female')) {
                     setIdOptions(prev => ({
                         ...prev,
                         gender: 'female',
                         clothing: null,
                         hairStyle: null
                     }));
                }
            } catch (analyzeError) {
                console.error("Auto analysis failed", analyzeError);
                // Non-blocking error, user can still manually select
            } finally {
                setIsAnalyzing(false);
            }
        }
        // --- AUTO ANALYSIS END ---

    } catch (e) {
        setError('Không thể đọc tệp ảnh.');
        console.error(e);
    }
  }, [mode]); // Added dependency on mode

  const handleBackgroundUpload = async (event: React.ChangeEvent<HTMLInputElement>) => {
        const file = event.target.files?.[0];
        if (!file) return;

        if (!file.type.startsWith('image/')) {
            setError('Vui lòng tải lên một tệp ảnh nền hợp lệ (PNG, JPG).');
            return;
        }

        try {
            const base64 = await fileToBase64(file);
            setCustomBackgroundImage({ base64, mimeType: file.type, name: file.name });
        } catch (e) {
            setError('Không thể đọc tệp ảnh nền.');
